"},"$:/config/rimir/namespace/walk-up":{"title":"$:/config/rimir/namespace/walk-up","text":"no"},"$:/plugins/rimir/namespace/context-widget.js":{"title":"$:/plugins/rimir/namespace/context-widget.js","text":"/*\
title: $:/plugins/rimir/namespace/context-widget.js
type: application/javascript
module-type: widget

$context widget — sets the `ns-context` variable for its children.

Usage:

  <$context prefix="OWASP/ASVS/4.0.3">
    [[V3.3]] here resolves to OWASP/ASVS/4.0.3/V3.3
  </$context>

Used both directly by authors and as the target of the \context pragma
(which wraps the rest of the tiddler in a $context widget at parse time).

\*/

"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var ContextWidget = function(parseTreeNode, options) {
	this.initialise(parseTreeNode, options);
};

ContextWidget.prototype = new Widget();

ContextWidget.prototype.render = function(parent, nextSibling) {
	this.parentDomNode = parent;
	this.computeAttributes();
	this.execute();
	this.renderChildren(parent, nextSibling);
};

ContextWidget.prototype.execute = function() {
	var prefix = this.getAttribute("prefix", "");
	if(prefix) { this.setVariable("ns-context", prefix); }
	this.makeChildWidgets();
};

ContextWidget.prototype.refresh = function(changedTiddlers) {
	var changedAttributes = this.computeAttributes();
	if(Object.keys(changedAttributes).length) {
		this.refreshSelf();
		return true;
	}
	return this.refreshChildren(changedTiddlers);
};

exports.context = ContextWidget;
","type":"application/javascript","module-type":"widget"},"$:/plugins/rimir/namespace/examples/aliases":{"title":"$:/plugins/rimir/namespace/examples/aliases","text":"! Aliases — short tokens → long paths

Aliases rewrite a whole reference //before// pseudo-segment expansion.
Two shapes:

* ''Exact'' — tiddlers tagged `$:/tags/NamespaceAlias` with fields
  `short` (the token users type) and `expands-to` (the rewrite).
  O(1) lookup.
* ''Pattern'' — tiddlers tagged `$:/tags/NamespacePatternAlias` with
  `pattern` (JS regex) and `replacement` (substitution, supports `$1`…`$9`).
  Tried in order; first match wins.

Exact beats pattern. The rewrite is re-run up to 3 times for chained
aliases (cycle safety), then pseudo expansion runs on the final ref.

!! Shipped example aliases

This plugin ships two demo aliases:

* Exact: [[$:/plugins/rimir/namespace/examples/data/aliases/exact-NS_V3.3]]
  — `NS_V3.3` → `…/examples/data/versions/_latest/V3.3`
* Pattern: [[$:/plugins/rimir/namespace/examples/data/aliases/pattern-NS_V]]
  — `NS_V<anything>` → `…/examples/data/versions/_latest/V<anything>`

!! Live references

With the exact alias alone:

* [[NS_V3.3]] — resolves via exact alias → `…/4.0.3/V3.3`

With the pattern alias:

* [[NS_V3.3]] — exact still wins (O(1) lookup beats pattern)
* [[NS_V4.2]] — exact doesn't match; pattern catches it → `…/4.0.3/V4.2`

Non-matching refs fall through:

* [[NS_nothing]] — no exact, pattern doesn't match `V…` → unresolved (⚠)

!! Precedence recap

For every link:

# ''Literal on raw REF first'' — a real tiddler named `NS_V3.3` would
  beat the alias. This avoids silent redirection if you accidentally
  name a tiddler the same as an alias.
# Alias rewrite (exact, then pattern).
# Pseudo expansion of the rewritten ref.
# Normal literal / context / walk-up pipeline.

!! Writing your own

Create a tiddler with the appropriate tag. No JS required:

''Exact:''

```
title: my-aliases/project-x
tags: $:/tags/NamespaceAlias
short: PX
expands-to: projects/projectX/_latest
```

→ `[[PX]]` now resolves via the latest `projectX` version.

''Pattern:''

```
title: my-aliases/OWASP-ASVS
tags: $:/tags/NamespacePatternAlias
pattern: ^OWASP_V(.+)$
replacement: OWASP/ASVS/_latest/V$1
```

→ `[[OWASP_V3.3]]`, `[[OWASP_V4.2]]`, etc. all resolve via the latest
ASVS version.

!! Gotchas

* ''Patterns are not auto-anchored.'' Use `^…$` if you want the whole
  ref to match. Otherwise `NS_V(.+)` also fires inside longer refs.
* ''Invalid regex'' in a pattern alias is logged to the console and the
  alias is skipped (not fatal).
* ''Chained aliases'' stop after 3 hops — prevents infinite loops if
  `A → B → A`.
* ''Core backlink index'' still only sees the literal (pre-alias) ref.
  An upcoming stage adds an indexer that'll capture resolved targets.
"},"$:/plugins/rimir/namespace/examples/backlinks":{"title":"$:/plugins/rimir/namespace/examples/backlinks","text":"! Backlinks — reverse index of resolved targets

Core TiddlyWiki's backlink cascade and the `relink` plugin only see the
literal `[[REF]]` string you type. With the namespace resolver, the
actual target depends on the source tiddler's context, walk-up, aliases,
and so on — so core backlinks undercount.

This plugin ships a backlinks indexer that scans every tiddler body
(wikitext + markdown), resolves each `[[REF]]` reference with the source
tiddler's context, and keeps a reverse-map of `target → sources`.

!! The `NS Backlinks` tab

Open any tiddler's info sidebar (the `i` icon) and find the ''NS'' tab.
It shows every tiddler that references //this one// via any resolution
path — including walk-up, aliases, mounts, context, and transclusions.

Try it on shipped data:

* [[$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V3.3]] —
  open its info sidebar. The ''NS Backlinks'' tab lists tiddlers that
  resolve to it, including the aliases and mount demos that point at it
  via `_latest`.
* [[$:/plugins/rimir/namespace/examples/data/docs/api]] — the intro
  page references it via walk-up; this tab reveals that.

!! Filter operators

For scripting or custom views:

* `[<title>ns-backlinks[]]` — source tiddlers that reference `<title>`
* `[<title>ns-forwardlinks[]]` — targets referenced by `<title>`

Example uses:

```
<$list filter="[<currentTiddler>ns-backlinks[]]">
<$link to=<<currentTiddler>>/> ·
</$list>
```

!! How it works

* At startup, every wikitext/markdown tiddler is scanned once (deferred
  one tick so it doesn't block initial render).
* On each wiki change, only the changed tiddlers are re-indexed.
* The indexer detects per-source context from a `\context` pragma
  on the first non-blank body line, falling back to the `context`
  field. `<$context>` widget scoping is not tracked — documented as a
  known limitation.

!! Caveats

* ''Regex-based extraction.'' The indexer uses regex on the body to
  find `[[…]]` and `{{…}}` references. Inside code blocks / verbatim
  regions it may produce false positives. For the backlinks use case,
  extra edges are harmless.
* ''No `relink` integration.'' The `relink` plugin rewrites link text
  on tiddler rename. It operates on core TW's link scan and is not
  yet namespace-aware. Renaming a tiddler that's reachable via walk-up
  or `_latest` may leave stale refs that continue to auto-resolve via
  the new layout, or become unresolved if the layout doesn't support
  them any more — the indexer //will// reflect the new reality, but
  `relink` won't suggest rewrites for cases where it should.
* ''Transclusion targets.'' `{{target}}` transclusions are indexed via
  the same regex, but the core transcludeinline rule still sees only
  the literal target. Namespace-aware transclusion (so `{{V3.3}}` from
  a context-scoped source resolves like `[[V3.3]]` does) is deferred.
"},"$:/plugins/rimir/namespace/examples/context-field":{"title":"$:/plugins/rimir/namespace/examples/context-field","context":"$:/plugins/rimir/namespace/examples/data/versions/4.0.3","text":"! `context:` field — declarative, whole-tiddler

Set a `context` field on the tiddler (via the editor's field panel, an
import, or just a field line in a `.tid` file). The filter operator
reads it as a fallback when no widget variable is set.

This tiddler has:

```
context: $:/plugins/rimir/namespace/examples/data/versions/4.0.3
```

!! Resolved via the field

* [[V3.3]] → `…/versions/4.0.3/V3.3`
* [[V4.2]] → `…/versions/4.0.3/V4.2`

!! When to use

The field form is right when:

* You want the tiddler's context to //travel with it// — e.g. a template
  you'll apply or export somewhere else.
* You want it visible in the metadata pane, not buried in the body.
* You want it editable like any other field — searchable, relinkable,
  bulk-editable via typed forms.

!! Widget / pragma override

A `\context` pragma or an enclosing `<$context>` widget overrides the
field. This makes the pragma/widget an effective "pin" that freezes a
doc against a different context than the field says.
"},"$:/plugins/rimir/namespace/examples/context-pragma":{"title":"$:/plugins/rimir/namespace/examples/context-pragma","text":"\context $:/plugins/rimir/namespace/examples/data/versions/4.0.3

! `\context` pragma — declare once, resolve many

A `\context <prefix>` pragma at the top of a tiddler's body sets
`ns-context` for the entire tiddler. Bare-name references then try
`<context>/REF` before falling back to walk-up.

This tiddler declares:

```
\context $:/plugins/rimir/namespace/examples/data/versions/4.0.3
```

So every bare `[[REF]]` below resolves under that prefix first.

!! Resolved via context

* [[V3.3]] → `…/versions/4.0.3/V3.3`
* [[V4.2]] → `…/versions/4.0.3/V4.2`

!! Absolute references are unaffected

* [[Older V3.3|$:/plugins/rimir/namespace/examples/data/versions/3.0/V3.3]]
  — still the 3.0 variant.

!! "Pin it"

Swap the pragma prefix to `…/_latest` and the references drift with the
newest version. Use a fixed version like the one above when you want
stability; use `_latest` when you want recency.

!! Unresolved

* [[NotThere]] — no such tiddler at `.../4.0.3/NotThere` nor via
  walk-up — rendered ⚠.
"},"$:/plugins/rimir/namespace/examples/context-widget":{"title":"$:/plugins/rimir/namespace/examples/context-widget","text":"! `<$context>` widget — scoped context

Use `<$context prefix="X">…</$context>` to set a context for a //region//
of a tiddler rather than the whole thing. Outside the region, normal
walk-up resumes.

!! Example

Before any widget — walk-up only (nothing matches from //this// tiddler):

* [[V3.3]] — ⚠ unresolved

Scoped to version ''3.0'':

<$context prefix="$:/plugins/rimir/namespace/examples/data/versions/3.0">
* [[V3.3]] — resolves to `3.0/V3.3`
</$context>

Scoped to version ''4.0.3'':

<$context prefix="$:/plugins/rimir/namespace/examples/data/versions/4.0.3">
* [[V3.3]] — resolves to `4.0.3/V3.3`
* [[V4.2]] — resolves to `4.0.3/V4.2`
</$context>

After the widgets — no context again:

* [[V3.3]] — ⚠ unresolved

!! Nesting

Widgets stack the usual way: an inner `<$context>` overrides the outer
one for its region.

<$context prefix="$:/plugins/rimir/namespace/examples/data/versions/3.0">
- outer is 3.0: [[V3.3]] → `3.0/V3.3`

<$context prefix="$:/plugins/rimir/namespace/examples/data/versions/4.0.3">
- inner is 4.0.3: [[V3.3]] → `4.0.3/V3.3`
</$context>

- back to outer 3.0: [[V3.3]] → `3.0/V3.3`
</$context>

!! When to use

The widget is the right tool when //one// tiddler talks about two or more
contexts side-by-side — a comparison doc, a changelog spanning versions,
a tutorial that demonstrates multiple resolutions.
"},"$:/plugins/rimir/namespace/examples/custom-pseudo":{"title":"$:/plugins/rimir/namespace/examples/custom-pseudo","text":"! Writing your own pseudo-segment

Pseudo-segments are pluggable via the `rimir-ns-pseudo` module type.
`_latest` is one such module; you can ship more alongside or in a
dependent plugin.

!! Minimal example — `_first`

Save this as `$:/plugins/yourspace/yourname/pseudo/_first.js`:

```
/*\
title: $:/plugins/yourspace/yourname/pseudo/_first.js
type: application/javascript
module-type: rimir-ns-pseudo
\*/

var util = require("$:/plugins/rimir/namespace/resolver.js");

exports.name = "_first";

exports.resolve = function(prefix, wiki) {
    if(!prefix) { return null; }
    var kids = util.listImmediateChildren(prefix, wiki);
    kids.sort();
    return kids.length ? kids[0] : null;
};
```

After a server restart, `[[docs/_first/intro]]` from any source
resolves to the alphabetically-first immediate child under `docs/`,
then looks up `intro` underneath it.

!! Contract

* `exports.name` — the //full// segment string, including the leading
  underscore. This is the pseudo-name the user types in their ref.
* `exports.resolve(prefix, wiki)` — `prefix` is the `/`-joined segments
  before the pseudo (empty string if pseudo is at position 0). Return:
** a non-empty replacement segment (string) on success, or
** `null` to fail expansion (the whole reference becomes unresolved).

!! What the framework does for you

* Discovery — any module-type `rimir-ns-pseudo` is picked up at startup.
* Caching — results are cached per `(pseudoName, prefix, wiki)`. You
  don't implement caching.
* Invalidation — change events on any tiddler touching a cached prefix
  drop that prefix's entries. You don't implement invalidation either.

!! Utilities from `resolver.js`

* `listImmediateChildren(prefix, wiki)` — set of direct child segments
  under `<prefix>/`, across regular and shadow tiddlers. Most pseudos
  just filter/sort this list and pick one.
* `splitPath(title)` — splits a title into segments, treating `$:/…`
  titles with `$:` as the root segment.

!! Ideas to try

* `_oldest` — version-min (copy `_latest`, flip the sort).
* `_random` — pick a random child. Fun, but cache eats the randomness —
  useful only if the page is re-rendered fresh each time.
* `_today` — ignore prefix, return today's date. Useful as a segment
  like `diaries/_today/entry`.
* `_stable` — version-max that skips prereleases.
"},"$:/plugins/rimir/namespace/examples/data/aliases/exact-NS_V3.3":{"title":"$:/plugins/rimir/namespace/examples/data/aliases/exact-NS_V3.3","tags":"$:/tags/NamespaceAlias","short":"NS_V3.3","expands-to":"$:/plugins/rimir/namespace/examples/data/versions/_latest/V3.3","text":"Exact alias: `NS_V3.3` → `…/examples/data/versions/_latest/V3.3`.

The `short` field is the token users type; `expands-to` is the rewrite.
The expansion contains `_latest`, which the resolver expands on the fly
— so this alias tracks the newest version child.
"},"$:/plugins/rimir/namespace/examples/data/aliases/pattern-NS_V":{"title":"$:/plugins/rimir/namespace/examples/data/aliases/pattern-NS_V","tags":"$:/tags/NamespacePatternAlias","pattern":"^NS_V(.+)$","replacement":"$:/plugins/rimir/namespace/examples/data/versions/_latest/V$1","text":"Pattern alias: any `NS_V<anything>` →
`…/examples/data/versions/_latest/V<anything>`.

Anchored with `^…$` so the whole ref must match. The `$1` capture
in `replacement` comes from `(.+)` in `pattern`. Expansion goes through
pseudo expansion, so `_latest` drifts as versions appear.

Using a pattern means you don't need one alias tiddler per version —
one pattern covers V3.3, V4.2, V5.0, etc.
"},"$:/plugins/rimir/namespace/examples/data/docs/api":{"title":"$:/plugins/rimir/namespace/examples/data/docs/api","text":"! API

API reference. Reached from [[intro]] via walk-up — no need to spell
out the full `$:/plugins/rimir/namespace/examples/data/docs/api`
path.
"},"$:/plugins/rimir/namespace/examples/data/docs/architecture":{"title":"$:/plugins/rimir/namespace/examples/data/docs/architecture","text":"! Architecture

Reached from [[intro]] via walk-up. From //this// page, links like
[[api]] and [[intro]] also walk up to the adjacent pages.
"},"$:/plugins/rimir/namespace/examples/data/docs/intro":{"title":"$:/plugins/rimir/namespace/examples/data/docs/intro","text":"! Intro

This is the intro page for the //docs// example. It links to the
sibling [[api]] page by bare name — the resolver walks up this
tiddler's title prefix and finds `.../docs/api` there.

Also see: [[architecture]].
"},"$:/plugins/rimir/namespace/examples/data/mounts/versions":{"title":"$:/plugins/rimir/namespace/examples/data/mounts/versions","tags":"$:/tags/NamespaceMount","from":"ns-docs","to":"$:/plugins/rimir/namespace/examples/data/versions","text":"Mount point. The logical prefix `ns-docs` maps to the physical title
prefix `$:/plugins/rimir/namespace/examples/data/versions`. So a ref
like `[[ns-docs/4.0.3/V3.3]]` rewrites internally to the long form.
"},"$:/plugins/rimir/namespace/examples/data/versions/3.0/V3.3":{"title":"$:/plugins/rimir/namespace/examples/data/versions/3.0/V3.3","text":"V3.3 in version ''3.0'' (example data).
"},"$:/plugins/rimir/namespace/examples/data/versions/3.0.1/V3.3":{"title":"$:/plugins/rimir/namespace/examples/data/versions/3.0.1/V3.3","text":"V3.3 in version ''3.0.1'' (example data).
"},"$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V3.3":{"title":"$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V3.3","text":"V3.3 in version ''4.0.3'' (example data).
"},"$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V4.2":{"title":"$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V4.2","text":"V4.2 in version ''4.0.3'' only. Older versions do not have this.
"},"$:/plugins/rimir/namespace/examples/data/versions/4.0.3":{"title":"$:/plugins/rimir/namespace/examples/data/versions/4.0.3","text":"Index page for version ''4.0.3''. Exists so {{{ [[…/_latest]] }}}
(with no trailing segment) can resolve to something real.
"},"$:/plugins/rimir/namespace/examples/latest":{"title":"$:/plugins/rimir/namespace/examples/latest","text":"! `_latest` — version-max resolution

Any segment equal to `_latest` is replaced with the highest-version
immediate child of the preceding prefix. A "version" is plain
dotted-numeric with an optional `-prerelease`.

!! Example data

Under `$:/plugins/rimir/namespace/examples/data/versions/`:

* `3.0/V3.3`
* `3.0.1/V3.3`
* `4.0.3/V3.3`
* `4.0.3/V4.2` — only in 4.0.3, not in older versions

The highest-version child of `…/examples/data/versions/` is `4.0.3`.

!! References

* [[ns-examples latest/V3.3|$:/plugins/rimir/namespace/examples/data/versions/_latest/V3.3]]
  → resolves to `.../4.0.3/V3.3`
* [[ns-examples latest/V4.2|$:/plugins/rimir/namespace/examples/data/versions/_latest/V4.2]]
  → resolves to `.../4.0.3/V4.2`
* [[ns-examples latest index|$:/plugins/rimir/namespace/examples/data/versions/_latest]]
  → resolves to `.../4.0.3` (the index tiddler)

!! Fixed-version references still work, of course

* [[3.0 V3.3|$:/plugins/rimir/namespace/examples/data/versions/3.0/V3.3]]
* [[3.0.1 V3.3|$:/plugins/rimir/namespace/examples/data/versions/3.0.1/V3.3]]
* [[4.0.3 V3.3|$:/plugins/rimir/namespace/examples/data/versions/4.0.3/V3.3]]

!! Drift

If you create a `5.0` directory in your own wiki with a tiddler
titled `$:/plugins/rimir/namespace/examples/data/versions/5.0/V3.3`,
the first link above will flip to resolving against `5.0` — without
any reload or cache bust. (Try it from the `$:/ControlPanel` tiddlers
panel if curious.)

!! Unresolved

* [[missing leaf|$:/plugins/rimir/namespace/examples/data/versions/_latest/NotThere]]
  — `_latest` expands fine; the leaf doesn't exist → unresolved (⚠).
* [[no version children|$:/plugins/rimir/namespace/examples/data/docs/_latest/X]]
  — no version-shaped children under `.../docs/` → `_latest` can't expand → unresolved.
"},"$:/plugins/rimir/namespace/examples/mounts":{"title":"$:/plugins/rimir/namespace/examples/mounts","text":"! Mount points — logical prefix → physical prefix

Mount points map a short logical namespace prefix to a longer physical
one. Pure prefix rewrite — no regex required. Use them when you want a
clean, short top-level name for a deeply-nested tree.

Declare a mount by creating a tiddler tagged `$:/tags/NamespaceMount`:

```
title: my-mount
tags: $:/tags/NamespaceMount
from: ns-docs
to: $:/plugins/rimir/namespace/examples/data/versions
```

!! Shipped example

This plugin ships one demo mount:
[[$:/plugins/rimir/namespace/examples/data/mounts/versions]]

* `from: ns-docs`
* `to: $:/plugins/rimir/namespace/examples/data/versions`

!! Live references via the mount

* [[ns-docs]] — equals `from`, so rewrites to the bare `to` (which isn't
  a real tiddler here, so ⚠ unresolved — expected)
* [[ns-docs/4.0.3/V3.3]] — rewrites to `…/data/versions/4.0.3/V3.3` → resolves
* [[ns-docs/4.0.3/V4.2]] — rewrites to `…/data/versions/4.0.3/V4.2` → resolves
* [[ns-docs/_latest/V3.3]] — rewrites, then `_latest` expands to `4.0.3`
  → `…/data/versions/4.0.3/V3.3` → resolves
* [[ns-docs/3.0/V3.3]] — older version, still resolves

!! Rules

* ''Exact match'' — REF equals `from` → rewrites to `to`.
* ''Prefix match'' — REF starts with `from + "/"` → rewrites the prefix,
  keeps the rest.
* ''Longest-match wins'' — if two mounts could match (e.g. `foo` and
  `foo/bar`), the longer `from` takes precedence.
* ''One-pass'' — mount results do //not// get re-run through the mount
  table. Use aliases for chained/multi-step rewrites.

!! Mount vs alias — when to use which

* ''Alias'' — rewrites the whole ref. Good for standalone shortcuts:
  `NS_V3.3` → `…/versions/_latest/V3.3`. Exact lookup or regex pattern.
* ''Mount'' — rewrites a //prefix//. Good for renaming/shortening a
  whole subtree: `ns-docs/*` → `$:/plugins/.../versions/*`. Declarative,
  no regex.

Rule of thumb: use a mount when you have many refs sharing a common
prefix and you want //all// of them to see the rewrite; use an alias
for single named shortcuts or when the substitution is non-prefix.

!! Core use cases

# ''Stripping disk-path noise.'' If your titles on disk include
  `a/b/c/d/OWASP/ASVS/…` for organisational reasons, a mount
  `from: OWASP  to: a/b/c/d/OWASP` lets authors write `[[OWASP/ASVS/V3.3]]`
  while the physical titles stay long. (Better still: strip the prefix
  at the `tiddlywiki.files` layer so titles are clean to begin with —
  then you don't need the mount.)
# ''Short roots for deep trees.'' `docs` → `project-x/documentation/public`.
# ''Federation.'' `partner` → `imports/partner-company`.
# ''Renaming a subtree without rewriting every link.'' Point the mount
  at the new location; keep the old ref form working everywhere.
"},"$:/plugins/rimir/namespace/examples/walkup":{"title":"$:/plugins/rimir/namespace/examples/walkup","text":"! Walk-up — relative references climb the title prefix

When you write a bare reference `[[REF]]` (no slashes) inside a tiddler
whose title already encodes hierarchy, the resolver walks up that title
trying `<prefix>/REF` at each level until something exists.

!! Example

Open [[$:/plugins/rimir/namespace/examples/data/docs/intro]]. Its body
contains a plain `[[api]]` link. When rendered, the resolver tries:

# `$:/plugins/rimir/namespace/examples/data/docs/api` ← ''hit''
# (would have tried `$:/plugins/rimir/namespace/examples/data/api` next)
# `$:/plugins/rimir/namespace/examples/api`
# … eventually `$:/plugins/api`, then just `api`

The first hit wins, so the link resolves to the sibling `api` page
without you ever writing a full path.

!! Transcluded live

<$transclude tiddler="$:/plugins/rimir/namespace/examples/data/docs/intro" mode="block"/>

(the `[[api]]` and `[[architecture]]` links above are resolving via
walk-up —  hover them to see the targets, click to navigate).

!! Why this matters

If you later move or rename the enclosing folder, the sibling relationships
stay intact. References only need to be rewritten when //those// siblings
move, not when the containing hierarchy is reorganised above.

!! Intentionally unresolved

In a tiddler titled `a/b/c/d/X`, a bare `[[NoSuchThing]]` walks up through
five candidates. None match → the link renders with the `ns-unresolved`
style (wavy underline + ⚠).
"},"$:/plugins/rimir/namespace/examples":{"title":"$:/plugins/rimir/namespace/examples","caption":"examples","text":"! Live examples

These pages ship with the plugin and use its own bundled data tiddlers
as targets — so they work the moment you install the plugin, regardless
of what else is in your wiki.

Each page focuses on one feature. Click through:

# [[Walk-up resolution|$:/plugins/rimir/namespace/examples/walkup]] — the
  zero-config base case. Write `[[sibling]]` and let the resolver climb.
# [[`_latest` pseudo-segment|$:/plugins/rimir/namespace/examples/latest]] —
  version-max resolution; refs drift as new versions appear.
# [[`\context` pragma|$:/plugins/rimir/namespace/examples/context-pragma]] —
  declare a prefix once at the top of a tiddler.
# [[`<$context>` widget|$:/plugins/rimir/namespace/examples/context-widget]] —
  scope a context to part of a tiddler.
# [[`context:` field|$:/plugins/rimir/namespace/examples/context-field]] —
  declarative, tiddler-level.
# [[Aliases|$:/plugins/rimir/namespace/examples/aliases]] — short tokens
  rewritten to longer paths, exact and pattern.
# [[Mount points|$:/plugins/rimir/namespace/examples/mounts]] — logical
  prefix → physical prefix, for cleaner top-level names.
# [[Backlinks & pin-latest|$:/plugins/rimir/namespace/examples/backlinks]] —
  reverse index, filter operators, `NS` info tab, pin-`_latest` action.
# [[Custom pseudo-segment|$:/plugins/rimir/namespace/examples/custom-pseudo]] —
  write your own `_foo`.

! The data used by these examples

Under `$:/plugins/rimir/namespace/examples/data/`:

* `versions/3.0/V3.3`
* `versions/3.0.1/V3.3`
* `versions/4.0.3/V3.3`, `versions/4.0.3/V4.2`, `versions/4.0.3` (index)
* `docs/intro`, `docs/api`, `docs/architecture`
* `aliases/exact-NS_V3.3` (tagged `$:/tags/NamespaceAlias`)
* `aliases/pattern-NS_V` (tagged `$:/tags/NamespacePatternAlias`)
* `mounts/versions` (tagged `$:/tags/NamespaceMount`)

Open any of these and browse around — they're small, wired to the
examples, and demonstrate the resolver in its natural habitat.
"},"$:/plugins/rimir/namespace/featureflags.js":{"title":"$:/plugins/rimir/namespace/featureflags.js","text":"/*\
title: $:/plugins/rimir/namespace/featureflags.js
type: application/javascript
module-type: library

Cached feature-flag reader for optional resolver stages.

Five flags gate expensive or implicit pipeline stages. All default to
"no" (off). Users toggle them via config tiddlers in the plugin's
settings tab.

  $:/config/rimir/namespace/walk-up           — path walk-up
  $:/config/rimir/namespace/implicit-context   — context: field fallback
  $:/config/rimir/namespace/pseudo-expansion   — _latest and pseudo modules
  $:/config/rimir/namespace/aliases            — exact + pattern alias rewrite
  $:/config/rimir/namespace/self-prefix        — descendant resolution
                                                 (try "<source>/<ref>")

Reading tiddler text on every resolve() call would be expensive, so we
cache the four booleans and invalidate on wiki change events (startup.js
calls invalidate() when it detects a config tiddler in the change set).

\*/

"use strict";

var CONFIG_PREFIX = "$:/config/rimir/namespace/";
var FLAGS = ["walk-up", "implicit-context", "pseudo-expansion", "aliases", "self-prefix"];

// null = not yet read. Object maps flag name → boolean.
var cached = null;

function readFlags(wiki) {
	if(cached) { return cached; }
	cached = Object.create(null);
	for(var i = 0; i < FLAGS.length; i++) {
		var text = wiki.getTiddlerText(CONFIG_PREFIX + FLAGS[i], "no");
		cached[FLAGS[i]] = (text.trim().toLowerCase() === "yes");
	}
	return cached;
}

exports.isEnabled = function(flagName, wiki) {
	return !!readFlags(wiki)[flagName];
};

exports.invalidate = function() {
	cached = null;
};

/*
Check whether any config tiddler title appears in a TW changes object.
Used by startup.js to decide whether to invalidate + full-rebuild.
*/
exports.isConfigChange = function(changes) {
	for(var i = 0; i < FLAGS.length; i++) {
		if(changes[CONFIG_PREFIX + FLAGS[i]]) { return true; }
	}
	return false;
};
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/namespace/filter.js":{"title":"$:/plugins/rimir/namespace/filter.js","text":"/*\
title: $:/plugins/rimir/namespace/filter.js
type: application/javascript
module-type: filteroperator

Filter operators exposing the namespace resolver.

Usage from wikitext:

  [<ref>ns-resolve<currentTiddler>]
    → resolved title, or the original ref if unresolved
      (so the enclosing $link widget still has a valid target).

  [<ref>ns-resolve-class<currentTiddler>]
    → "tc-tiddlylink ns-resolved"    when resolution succeeded
    → "tc-tiddlylink ns-unresolved"  when it did not

Both operators take the source tiddler title as their operand, so the caller
passes <currentTiddler>. The input is the reference string.

Context lookup — before calling the resolver we look up a declared
"context prefix":

  1. Widget variable `ns-context` (set by the <$context> widget or the
     \context pragma) — always active.
  2. Field `context` on the source tiddler — only when the
     "implicit-context" feature flag is enabled.

The context is passed as options.context to the resolver. Widget variable
wins over field so that nested <$context> widgets and \context pragmas
override the tiddler-level default.

\*/

"use strict";

var resolver = require("$:/plugins/rimir/namespace/resolver.js");
var indexer = require("$:/plugins/rimir/namespace/indexer.js");
var flags = require("$:/plugins/rimir/namespace/featureflags.js");

function getContext(sourceTitle, options) {
	// Widget variable first (set by <$context> / \context pragma).
	if(options.widget && typeof options.widget.getVariable === "function") {
		var v = options.widget.getVariable("ns-context");
		if(v) { return v; }
	}
	// Fallback: context field on the source tiddler.
	// Gated by the "implicit-context" feature flag.
	if(flags.isEnabled("implicit-context", options.wiki)) {
		if(sourceTitle && options.wiki) {
			var t = options.wiki.getTiddler(sourceTitle);
			if(t && t.fields && t.fields.context) { return t.fields.context; }
		}
	}
	return "";
}

exports["ns-resolve"] = function(source, operator, options) {
	var sourceTitle = operator.operand || "",
		context = getContext(sourceTitle, options),
		results = [];
	source(function(tiddler, title) {
		var r = resolver.resolve(title, sourceTitle, options.wiki, {context: context});
		results.push(r.resolved || title);
	});
	return results;
};

exports["ns-resolve-class"] = function(source, operator, options) {
	var sourceTitle = operator.operand || "",
		context = getContext(sourceTitle, options),
		results = [];
	source(function(tiddler, title) {
		var r = resolver.resolve(title, sourceTitle, options.wiki, {context: context});
		if(r.status === "unresolved") {
			results.push("tc-tiddlylink ns-unresolved");
		} else {
			results.push("tc-tiddlylink ns-resolved");
		}
	});
	return results;
};

/*
[<title>ns-backlinks[]]
  → titles that reference `title` via any of literal, alias, mount,
    context, walk-up, pseudo-expanded, or transclusion. Sourced from
    the backlinks indexer — only accurate for indexable tiddlers
    (wikitext + markdown). Input titles are each looked up; outputs
    are union'd in sort order.
*/
exports["ns-backlinks"] = function(source, operator, options) {
	var results = {};
	source(function(tiddler, title) {
		var sources = indexer.getBacklinks(title);
		for(var i = 0; i < sources.length; i++) { results[sources[i]] = true; }
	});
	return Object.keys(results).sort();
};

/*
[<title>ns-forwardlinks[]]
  → titles that `title` references via the resolver. Diagnostic flip
    side of ns-backlinks.
*/
exports["ns-forwardlinks"] = function(source, operator, options) {
	var results = {};
	source(function(tiddler, title) {
		var targets = indexer.getForwardLinks(title);
		for(var i = 0; i < targets.length; i++) { results[targets[i]] = true; }
	});
	return Object.keys(results).sort();
};

/*
[<title>ns-pin-context[]]
  → title's body text with any `\context` pragma expanded (`_latest` and
    other pseudos resolved to current values). Non-destructive: returns
    the rewritten text; caller is responsible for persisting via
    $action-setfield. If no pragma or nothing to rewrite, returns the
    text unchanged.

    Typical use: <$button>
                   Pin _latest
                   <$action-setfield text={{{ [<currentTiddler>ns-pin-context[]] }}}/>
                 </$button>
*/
var RE_PRAGMA = /^(\s*\\context\s+)(\S+)(.*)$/m;
exports["ns-pin-context"] = function(source, operator, options) {
	var results = [];
	source(function(tiddler, title) {
		var t = options.wiki.getTiddler(title);
		if(!t || !t.fields) { results.push(""); return; }
		var text = t.fields.text || "";
		var m = text.match(RE_PRAGMA);
		if(!m) { results.push(text); return; }
		var prefix = m[2],
			expanded = resolver.expandPseudoSegments(prefix, options.wiki);
		if(!expanded || expanded === prefix) { results.push(text); return; }
		results.push(text.substring(0, m.index) + m[1] + expanded + m[3] + text.substring(m.index + m[0].length));
	});
	return results;
};
