"},"$:/plugins/rimir/namespace/indexer.js":{"title":"$:/plugins/rimir/namespace/indexer.js","text":"/*\
title: $:/plugins/rimir/namespace/indexer.js
type: application/javascript
module-type: library

Backlinks indexer — tracks which source tiddlers reference which
//resolved// targets. Core TW's backlink cascade only sees the literal
link text (e.g. `V3.3`) because our parser emits filtered `to`
attributes; this module gives you the real graph.

Scanning strategy: regex over the tiddler's `text` field for `[[REF]]`,
`[[label|REF]]`, and `{{REF}}` / `{{REF||template}}` forms. Cheap, has
occasional false positives inside code blocks — the trade-off is
acceptable for a backlinks view (extra edges never hurt lookup).

Per-source context detection:

  1. `\context <prefix>` pragma on the first non-blank body line (always).
  2. `context` field on the source tiddler (only when the
     "implicit-context" feature flag is enabled).
  3. No context.

The `<$context>` widget's scoped context is //not// tracked — backlinks
for refs inside a mid-body widget use the whole-tiddler context only.
Documented as a known limitation.

Change tracking: full rebuild on startup (idle, after 1 tick so other
startup modules finish first); incremental per change event. Refs
indexed for a given source are stored forward so we can remove them
cleanly on re-index.

\*/

"use strict";

var resolver = require("$:/plugins/rimir/namespace/resolver.js");
var flags = require("$:/plugins/rimir/namespace/featureflags.js");

// Forward: sourceTitle → Set<targetTitle>
// (so we can remove a source's old edges on re-index cleanly).
var forward = Object.create(null);
// Reverse: targetTitle → Set<sourceTitle>
var reverse = Object.create(null);

function addEdge(source, target) {
	if(!forward[source]) { forward[source] = Object.create(null); }
	forward[source][target] = true;
	if(!reverse[target]) { reverse[target] = Object.create(null); }
	reverse[target][source] = true;
}

function removeSource(source) {
	var targets = forward[source];
	if(!targets) { return; }
	for(var target in targets) {
		if(reverse[target]) {
			delete reverse[target][source];
			// Leave empty object rather than deleting — negligible memory,
			// keeps shape stable for callers that iterate.
		}
	}
	delete forward[source];
}

// Regexes are deliberately forgiving — extra spurious matches cost
// nothing, missed matches cost backlinks.
var RE_PRETTYLINK = /\[\[(?:[^\]|\n]*\|)?([^\]\n]+)\]\]/g;
// {{REF}} and {{REF||template}} but NOT {{{filter}}} (triple-brace).
var RE_TRANSCLUDE = /(^|[^{])\{\{([^{}|][^{}|]*)(?:\|\|[^{}]*)?\}\}(?!\})/g;
var RE_CONTEXT_PRAGMA = /^\s*\\context\s+(\S+)/m;

function extractRefs(text) {
	var refs = [];
	if(!text) { return refs; }
	var m;
	RE_PRETTYLINK.lastIndex = 0;
	while((m = RE_PRETTYLINK.exec(text)) !== null) { refs.push(m[1]); }
	RE_TRANSCLUDE.lastIndex = 0;
	while((m = RE_TRANSCLUDE.exec(text)) !== null) { refs.push(m[2]); }
	return refs;
}

function detectContext(tiddler, wiki) {
	if(!tiddler || !tiddler.fields) { return ""; }
	// Field-based context gated by the "implicit-context" feature flag.
	if(flags.isEnabled("implicit-context", wiki) && tiddler.fields.context) {
		return tiddler.fields.context;
	}
	var text = tiddler.fields.text || "";
	var m = text.match(RE_CONTEXT_PRAGMA);
	return m ? m[1] : "";
}

function isIndexable(tiddler) {
	if(!tiddler || !tiddler.fields) { return false; }
	var type = tiddler.fields.type;
	// wikitext (unset or vnd.tiddlywiki) and markdown carry our syntax.
	// Everything else (JSON data, images, css, js, code) is skipped.
	if(!type || type === "text/vnd.tiddlywiki" || type === "text/x-markdown") {
		return true;
	}
	return false;
}

function indexSource(title, wiki) {
	removeSource(title);
	var tiddler = wiki.getTiddler(title);
	if(!isIndexable(tiddler)) { return; }
	var refs = extractRefs(tiddler.fields.text);
	if(!refs.length) { return; }
	var context = detectContext(tiddler, wiki),
		opts = context ? {context: context} : undefined;
	for(var i = 0; i < refs.length; i++) {
		var r = resolver.resolve(refs[i], title, wiki, opts);
		if(r.resolved) { addEdge(title, r.resolved); }
	}
}

/*
Index all tiddlers + shadows. Safe to call multiple times — each source
is cleaned up before re-indexing. Expensive but linear in wiki size;
call from startup (once) and on bulk changes.
*/
exports.rebuildAll = function(wiki) {
	forward = Object.create(null);
	reverse = Object.create(null);
	if(wiki.each) {
		wiki.each(function(tiddler, title) { indexSource(title, wiki); });
	}
	if(wiki.eachShadow) {
		wiki.eachShadow(function(tiddler, title) { indexSource(title, wiki); });
	}
};

/*
Re-index a single source tiddler. If the tiddler no longer exists or
isn't indexable, its edges are dropped.
*/
exports.reindex = function(title, wiki) {
	indexSource(title, wiki);
};

/*
Bulk re-index — for change events with multiple changed titles.
*/
exports.reindexMany = function(titles, wiki) {
	for(var i = 0; i < titles.length; i++) { indexSource(titles[i], wiki); }
};

/*
Return an array of source titles that reference `target` (via whatever
route — literal, alias, mount, context, walk-up). Sorted alphabetically
for stable output.
*/
exports.getBacklinks = function(target) {
	var sources = reverse[target];
	if(!sources) { return []; }
	return Object.keys(sources).sort();
};

/*
Return the resolved targets a source tiddler currently references.
Useful for diagnostics and for the settings tab.
*/
exports.getForwardLinks = function(source) {
	var targets = forward[source];
	if(!targets) { return []; }
	return Object.keys(targets).sort();
};

/*
Empty the index. Tests use this between wikis; normal runtime doesn't
need it (the startup hook calls rebuildAll which is idempotent).
*/
exports.reset = function() {
	forward = Object.create(null);
	reverse = Object.create(null);
};
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/namespace/mounts.js":{"title":"$:/plugins/rimir/namespace/mounts.js","text":"/*\
title: $:/plugins/rimir/namespace/mounts.js
type: application/javascript
module-type: library

Mount-point rewrites — map a logical namespace prefix to a physical one.

Declarative via tiddlers tagged `$:/tags/NamespaceMount`:

    from:  logical prefix users type (required, no trailing slash)
    to:    physical prefix the ref rewrites to (required)

A mount fires when the incoming REF either:
  * equals `<from>` exactly → rewritten to `<to>`, or
  * starts with `<from>/`   → rewritten to `<to>/<rest>`

Longest `from` wins when multiple mounts match — most-specific beats
most-general. Unlike pattern aliases, mounts are strictly prefix-based
and need no regex: the common "map a namespace root" use case without
the footgun.

The rewritten REF continues through the resolver pipeline, so mount
results go through pseudo expansion (`_latest` etc.) and the normal
literal / context / walk-up lookup.

Cache is built lazily on first use and dropped whole on any wiki change
(startup.js hooks this). Rebuild cost is O(M) over mount-tagged tiddlers,
typically tiny.

\*/

"use strict";

var MOUNT_TAG = "$:/tags/NamespaceMount";

// Cache keyed per-wiki (WeakMap) so multiple concurrent wikis don't
// share stale entries. Entry = sorted array of {from, to, title},
// longest `from` first.
var caches = typeof WeakMap !== "undefined" ? new WeakMap() : null;

function buildCache(wiki) {
	var entry = caches && caches.get(wiki);
	if(entry) { return entry; }
	entry = [];
	var titles = wiki.filterTiddlers("[all[tiddlers+shadows]tag[" + MOUNT_TAG + "]]");
	for(var i = 0; i < titles.length; i++) {
		var t = wiki.getTiddler(titles[i]);
		if(!t || !t.fields) { continue; }
		var from = t.fields["from"],
			to = t.fields["to"];
		if(typeof from !== "string" || !from) { continue; }
		if(typeof to !== "string" || !to) { continue; }
		// Normalise: drop any leading or trailing slash on `from` so users
		// can be sloppy. `to` is used verbatim (might intentionally include
		// a trailing separator somewhere).
		from = from.replace(/^\/+/, "").replace(/\/+$/, "");
		if(!from) { continue; }
		entry.push({from: from, to: to, title: titles[i]});
	}
	// Longest from first — ensures the most-specific mount wins when
	// two mounts could both match (e.g. `OWASP` vs `OWASP/ASVS`).
	entry.sort(function(a, b) { return b.from.length - a.from.length; });
	if(caches) { caches.set(wiki, entry); }
	return entry;
}

/*
Apply mount rewrites to REF. Returns the rewritten REF, or null if no
mount matched. One-pass: mount results don't get re-run through the
mount table to avoid cascades. (Use aliases for multi-step rewrites.)
*/
exports.resolveMount = function(ref, wiki) {
	if(!ref) { return null; }
	var cache = buildCache(wiki);
	for(var i = 0; i < cache.length; i++) {
		var m = cache[i];
		if(ref === m.from) { return m.to; }
		if(ref.length > m.from.length + 1 &&
		   ref.substring(0, m.from.length + 1) === m.from + "/") {
			return m.to + "/" + ref.substring(m.from.length + 1);
		}
	}
	return null;
};

/*
Drop the mount cache. With no wiki argument, drops every wiki's cache.
*/
exports.invalidateMounts = function(wiki) {
	if(!caches) { return; }
	if(wiki) { caches.delete(wiki); } else { caches = new WeakMap(); }
};
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/namespace/pragma.js":{"title":"$:/plugins/rimir/namespace/pragma.js","text":"/*\
title: $:/plugins/rimir/namespace/pragma.js
type: application/javascript
module-type: wikirule

Pragma rule for `\context <prefix>`.

Appears at the top of a tiddler (in the pragma section, alongside
\define / \procedure / \parameters / etc.). Wraps the rest of the
tiddler body in a $context widget so `ns-context` is set for every
[[REF]] rendered inside.

```
\context OWASP/ASVS/4.0.3

this tiddler's [[V3.3]] now resolves via the declared context.
```

\*/

"use strict";

exports.name = "namespacecontext";
exports.types = {pragma: true};

exports.init = function(parser) {
	this.parser = parser;
	// \context <prefix> up to end of line. Prefix must not contain whitespace.
	this.matchRegExp = /\\context\s+(\S+)[^\S\n]*(\r?\n)?/mg;
};

exports.parse = function() {
	this.parser.pos = this.matchRegExp.lastIndex;
	var prefix = this.match[1];
	// Emit a single $context node. The wikiparser's parsePragmas() auto-
	// wraps subsequent parse output as our children — so our widget's
	// ns-context variable is in scope for the entire remaining body.
	var attr = {name: "prefix", type: "string", value: prefix};
	return [{
		type: "context",
		attributes: {prefix: attr},
		orderedAttributes: [attr]
	}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/rimir/namespace/prettylink.js":{"title":"$:/plugins/rimir/namespace/prettylink.js","text":"/*\
title: $:/plugins/rimir/namespace/prettylink.js
type: application/javascript
module-type: wikirule

Namespace-aware replacement for the core `[[…]]` / `[[text|target]]` rule.

Matches the same regex as core prettylink. For external links, behaves
identically to core. For internal links, emits AST equivalent to:

  <$let __nsref__="REF"
        __nssrc__={{{ [<thisTiddler>!is[blank]] ~[<currentTiddler>] }}}>
    <$link to={{{ [<__nsref__>ns-resolve<__nssrc__>] }}}
           class={{{ [<__nsref__>ns-resolve-class<__nssrc__>] }}}>
      text
    </$link>
  </$let>

The $let scopes a fresh variable per link so the filter attributes can
pull the raw ref without collisions across sibling links in the same
tiddler. Resolution happens at render time via the ns-resolve filter
operator.

Source-title selection: TW 5.4.0+ `<$transclude $tiddler=...>` sets
`thisTiddler` (not `currentTiddler`), so we prefer thisTiddler and fall
back to currentTiddler. This makes walk-up work whether the wikitext
is rendered via story river (only currentTiddler is set), via a plain
$tiddler widget wrapper, or via $transclude (only thisTiddler is set).

The core rule is disabled via a config tiddler shipped with this plugin;
our rule uses a distinct name to avoid any registration collision.

\*/

"use strict";

exports.name = "namespaceprettylink";
exports.types = {inline: true};

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = /\[\[(.*?)(?:\|(.*?))?\]\]/mg;
};

exports.parse = function() {
	var start = this.parser.pos + 2;
	this.parser.pos = this.matchRegExp.lastIndex;
	var text = this.match[1],
		link = this.match[2] || text,
		textEndPos = this.parser.source.indexOf("|", start);
	if(textEndPos < 0 || textEndPos > this.matchRegExp.lastIndex) {
		textEndPos = this.matchRegExp.lastIndex - 2;
	}
	var linkStart = this.match[2] ? (start + this.match[1].length + 1) : start,
		linkEnd = linkStart + link.length;
	// External links bypass the namespace machinery entirely.
	if($tw.utils.isLinkExternal(link)) {
		return [{
			type: "element",
			tag: "a",
			attributes: {
				href: {type: "string", value: link, start: linkStart, end: linkEnd},
				"class": {type: "string", value: "tc-tiddlylink-external"},
				target: {type: "string", value: "_blank"},
				rel: {type: "string", value: "noopener noreferrer"}
			},
			children: [{type: "text", text: text, start: start, end: textEndPos}]
		}];
	}
	// Internal link: wrap in $let so each link has its own __nsref__ +
	// __nssrc__ scope, then render via $link with filtered to/class
	// attributes. __nssrc__ resolves to thisTiddler (preferred — set by
	// $transclude), or currentTiddler (set by $tiddler widget / story).
	// Note: LetWidget reads `name` from each attribute VALUE object (via
	// getOrderedAttributesFromParseTreeNode), unlike the base Widget which
	// uses the attribute KEY — so we must set `name` explicitly here.
	return [{
		type: "let",
		attributes: {
			"__nsref__": {name: "__nsref__", type: "string", value: link, start: linkStart, end: linkEnd},
			"__nssrc__": {name: "__nssrc__", type: "filtered", filter: "[<thisTiddler>!is[blank]] ~[<currentTiddler>]"}
		},
		children: [{
			type: "link",
			attributes: {
				to:      {type: "filtered", filter: "[<__nsref__>ns-resolve<__nssrc__>]"},
				"class": {type: "filtered", filter: "[<__nsref__>ns-resolve-class<__nssrc__>]"}
			},
			children: [{type: "text", text: text, start: start, end: textEndPos}]
		}]
	}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/rimir/namespace/pseudo/_latest.js":{"title":"$:/plugins/rimir/namespace/pseudo/_latest.js","text":"/*\
title: $:/plugins/rimir/namespace/pseudo/_latest.js
type: application/javascript
module-type: rimir-ns-pseudo

Pseudo-segment `_latest` — resolves to the highest-version immediate
child of the preceding prefix.

A "version" is a plain dotted-numeric string optionally suffixed with
`-prerelease`. Examples: `1`, `3.0`, `4.0.3`, `1.0-beta`, `2.0.0-rc.1`.
Comparison is numeric per segment (missing = 0), with releases sorting
above their prereleases. Non-version siblings are ignored.

Returns null if the prefix is empty (no anchor for version lookup) or
no version-shaped children exist.

\*/

"use strict";

var util = require("$:/plugins/rimir/namespace/resolver.js");

exports.name = "_latest";

var RE_VERSION = /^\d+(\.\d+)*(-[\w.]+)?$/;

function isVersion(s) {
	return typeof s === "string" && RE_VERSION.test(s);
}

function compareVersions(a, b) {
	var aParts = a.split("-"),
		bParts = b.split("-"),
		aNums = aParts[0].split("."),
		bNums = bParts[0].split("."),
		len = Math.max(aNums.length, bNums.length);
	for(var i = 0; i < len; i++) {
		var aN = parseInt(aNums[i] || "0", 10),
			bN = parseInt(bNums[i] || "0", 10);
		if(aN !== bN) { return aN - bN; }
	}
	var aPre = aParts.slice(1).join("-"),
		bPre = bParts.slice(1).join("-");
	if(!aPre && !bPre) { return 0; }
	if(!aPre) { return 1; }   // release > prerelease
	if(!bPre) { return -1; }
	return aPre < bPre ? -1 : (aPre > bPre ? 1 : 0);
}

exports.resolve = function(prefix, wiki) {
	if(!prefix) { return null; }
	var versions = util.listImmediateChildren(prefix, wiki).filter(isVersion);
	if(!versions.length) { return null; }
	versions.sort(compareVersions);
	return versions[versions.length - 1];
};
","type":"application/javascript","module-type":"rimir-ns-pseudo"},"$:/plugins/rimir/namespace/readme":{"title":"$:/plugins/rimir/namespace/readme","text":"! Namespace

Namespace-aware link resolution for TiddlyWiki. Replaces the core
{{{ [[…]] }}} parser rule so link targets are resolved relative to the
source tiddler's own title prefix — with declarative overrides and
pluggable pseudo-segments.

The plugin is ''explicit-first'': advanced features (walk-up, aliases,
pseudo-expansion, implicit context) are all off by default and can be
toggled individually in the [[settings tab|$:/plugins/rimir/namespace/settings]].
The core mechanism — literal match + `\context` pragma / `<$context>` widget +
mount points — is always active.

→ ''See the [[examples tab|$:/plugins/rimir/namespace/examples]]''
for live, in-plugin demos of every feature described below.

!! Resolution pipeline

A link {{{ [[REF]] }}} is resolved in this order. Stages marked ☐ are
off by default and activated via feature flags in settings.

# ''Literal on raw REF'' — a real tiddler always beats an alias or
  pseudo expansion. Avoids silent redirection if a tiddler and an alias
  share a name.
# ☐ ''Alias rewrite'' — exact aliases (tiddlers tagged
  `$:/tags/NamespaceAlias` with `short` + `expands-to` fields) and
  pattern aliases (`$:/tags/NamespacePatternAlias`, `pattern` +
  `replacement`). Chained up to 3 hops for cycle safety.
# ''Mount rewrite'' — `$:/tags/NamespaceMount` with `from` / `to`.
  Longest `from` wins; one-pass (no cascading).
# ☐ ''Pseudo-segment expansion'' — any segment starting with `_` is
  looked up in the pseudo-registry. Matching resolvers receive
  `(prefix, wiki)` and return a replacement segment or null.
# ''Literal on expanded REF'' — catches the aliased, mounted, or
  pseudo-expanded forms.
# ''$:/ short-circuit'' — refs starting with `$:/` are treated as
  absolute system titles: literal-only, never contextualized or walked.
# ''Context prefix'' — if a context is declared (see below), try
  `<context>/REF`. When pseudo-expansion is enabled, pseudo-segments
  inside the context are also expanded.
# ☐ ''Self-prefix'' — try `<sourceTitle>/REF`. Resolves descendant
  refs in deep namespaces. Walk-up never finds descendants (it only
  walks up parents), so this is the explicit hook for that case.
# ☐ ''Walk-up'' — walk up the source tiddler's title prefix:
  from //source// `a/b/c/d/X`, try `a/b/c/d/REF`, `a/b/c/REF`,
  `a/b/REF`, `a/REF`, `REF`. First hit wins.
# ''Unresolved'' — rendered with the `ns-unresolved` class
  (wavy underline + ⚠ marker).

!! Feature flags

Five optional features can be toggled in the
[[settings tab|$:/plugins/rimir/namespace/settings]]. All are ''off'' by
default. No server restart required — toggling a flag takes effect
immediately.

|!Flag |!What it enables |
|Walk-up |Path-based walk-up from source tiddler (ancestors) |
|Self-prefix |`<sourceTitle>/REF` lookup (descendants) |
|Implicit context |`context:` field fallback (in addition to `\context` pragma / `<$context>` widget) |
|Pseudo expansion |`_latest` and other `_foo` pseudo-segment modules |
|Aliases |Exact + pattern alias resolution |

!! Declaring a context

Two always-on mechanisms, plus an optional field-based fallback:

* ''Pragma at the top of a tiddler'' (always active):

```
\context OWASP/ASVS/4.0.3

now [[V3.3]] resolves to OWASP/ASVS/4.0.3/V3.3
```

* ''Widget for a scoped region'' (always active):

```
<$context prefix="OWASP/ASVS/4.0.3">
  [[V3.3]] resolves here
</$context>
regular rendering resumes outside
```

* ''Field on the tiddler'' (requires ''implicit context'' flag):

```
title: my-notes
context: OWASP/ASVS/4.0.3
...
```

Priority: widget variable (from pragma or `<$context>`) wins over field.
That makes `\context` an effective "pin" — dropping `\context OWASP/ASVS/4.0.3`
at the top of a doc overrides any field-based context and freezes the
doc's resolutions against version 4.0.3.

!! Aliases — short tokens for common refs

Create a tiddler tagged `$:/tags/NamespaceAlias`:

```
short: OWASP_V3.3
expands-to: OWASP/ASVS/_latest/V3.3
```

Now {{{ [[OWASP_V3.3]] }}} from anywhere resolves via the alias +
`_latest` expansion.

For many similar refs, use a pattern alias (tag
`$:/tags/NamespacePatternAlias`):

```
pattern: ^OWASP_V(.+)$
replacement: OWASP/ASVS/_latest/V$1
```

Now `OWASP_V3.3`, `OWASP_V4.2`, `OWASP_V5.0`, … all resolve.

Exact beats pattern. See the [[examples tab|$:/plugins/rimir/namespace/examples/aliases]]
for live demos.

!! Mount points — short prefixes for deep subtrees

For a whole subtree rather than a single token, use a mount
(tag `$:/tags/NamespaceMount`):

```
from: docs
to: project-x/documentation/public
```

Now `[[docs/intro]]`, `[[docs/api/v2]]`, etc. rewrite to
`project-x/documentation/public/intro`, `…/api/v2`, and so on. Longest
`from` wins when multiple mounts could match. See the
[[Mount points example|$:/plugins/rimir/namespace/examples/mounts]].

!! Built-in pseudo-segments

* ''`_latest`'' — resolves to the highest-version immediate child of its
  prefix. A "version" is plain dotted-numeric with optional `-prerelease`
  (`1`, `3.0`, `4.0.3`, `1.0-beta`, `2.0.0-rc.1`). Comparison is numeric
  per segment, with releases sorting above their prereleases.

!! Examples

''Walk-up from a deep title.'' A tiddler titled
`a/b/OWASP/ASVS/4.0.3/docs/intro` can write {{{ [[V3.3]] }}} and it
resolves to `a/b/OWASP/ASVS/4.0.3/V3.3`.

''`_latest` at a fixed anchor.'' A reference
{{{ [[OWASP/ASVS/_latest/V3.3]] }}} resolves to
`OWASP/ASVS/4.0.3/V3.3` when `4.0.3` is the highest version child under
`OWASP/ASVS/`. Add `5.0` and the same reference re-points.

''Context + bare ref.'' From any tiddler:

```
\context OWASP/ASVS/_latest
[[V3.3]]   ← resolves via context → OWASP/ASVS/<max>/V3.3
[[V4.2]]   ← same, but if missing in <max>, link is unresolved
```

!! Adding your own pseudo-segment

Pseudo-segments are pluggable. Drop a JS module alongside or in a
dependent plugin, declaring `module-type: rimir-ns-pseudo`:

```
/*\
title: $:/plugins/yourspace/yourname/pseudo/_first.js
type: application/javascript
module-type: rimir-ns-pseudo
\*/

var util = require("$:/plugins/rimir/namespace/resolver.js");

exports.name = "_first";

exports.resolve = function(prefix, wiki) {
    if(!prefix) { return null; }
    var kids = util.listImmediateChildren(prefix, wiki);
    kids.sort();
    return kids.length ? kids[0] : null;
};
```

After a server restart, {{{ [[docs/_first/intro]] }}} from any source
resolves to the alphabetically first immediate child under `docs/`.

''The contract:''

* `exports.name` — the full segment string, //including// the leading
  underscore. This is what appears in the user's reference.
* `exports.resolve(prefix, wiki)` — `prefix` is the `/`-joined segments
  before the pseudo (empty string if pseudo is at position 0). Return
  the replacement segment (non-empty string) or `null` to fail
  expansion.

''Utilities available from `resolver.js`:''

* `listImmediateChildren(prefix, wiki)` — returns the set of immediate
  child segments under `<prefix>/`, across regular and shadow tiddlers.
* `splitPath(title)` — splits a title into path segments, treating
  `$:/…` titles as a single segment.

Results are cached per `(pseudoName, prefix, wiki)` triple; the cache is
invalidated on wiki change events whose title touches the prefix.

!! How link rendering works

The wikirule converts {{{ [[REF]] }}} into:

```
<$let __nsref__="REF">
  <$link to={{{ [<__nsref__>ns-resolve<currentTiddler>] }}}
         class={{{ [<__nsref__>ns-resolve-class<currentTiddler>] }}}>
    text
  </$link>
</$let>
```

Resolution happens at render time via the `ns-resolve` filter operator,
which reads the `ns-context` variable (set by pragma or widget) with
fallback to the `context` field of `currentTiddler`. Because the
`currentTiddler` is the rendering context, references resolve correctly
under transclusion.

!! Backlinks & tooling

The plugin maintains its own backlinks index, built from a per-tiddler
scan that resolves every reference with the source tiddler's context.
Exposed as:

* Filter operator `[<title>ns-backlinks[]]` — sources that reference
  `<title>`.
* Filter operator `[<title>ns-forwardlinks[]]` — targets referenced by
  `<title>`.
* ''NS'' tab in the tiddler info sidebar — lists both, plus a
  ''Pin `_latest`'' button for tiddlers whose `\context` pragma contains
  drifting pseudos.

A ''settings'' plugin tab lists all registered pseudos, aliases, and
mount points for diagnostics.

!! Relink integration

When the [[relink plugin|https://github.com/flibbles/tw5-relink]] is
installed, renaming a tiddler automatically updates:

* `\context <prefix>` pragmas where the prefix matches the old title.
* `<$context prefix="...">` widget attributes.
* ''Namespace-resolved `[[REF]]` references'' — short refs whose
  current resolution (literal / walk-up / context / self-prefix) points
  to the renamed tiddler. Refs that still resolve correctly post-rename
  are left alone. Otherwise the rule searches for the shortest suffix of
  the new title that resolves correctly from the source (e.g. rename
  `a/b/c/d` → `a/b/c/e` from source `a/b/c` rewrites `[[d]]` to
  `[[e]]`). When even the full title is the only valid form, the ref
  is pinned with a label-preserving form like `[[bar|knowledge/ai/bar]]`.
  Absolute literal refs always rewrite cleanly:
  `[[knowledge/llm/foo]]` → `[[knowledge/ai/foo]]`.

Combined with the ''relink-titles'' companion plugin (which cascades
renames to child tiddlers), renaming a parent like `OWASP/ASVS` to
`OWASP/Standards` also updates `\context OWASP/ASVS/4.0.3` →
`\context OWASP/Standards/4.0.3` (because relink-titles renames the
child tiddler first, then relink updates the reference). Internal short
refs across the moved subtree get pinned to absolute on the way; once
the cascade settles they remain valid (and you can re-shorten manually
if you prefer the brief form).

!! Deferred

* Namespace-aware transclusion `{{REF}}` — would require a full core
  transcludeinline replacement to cover template / field / index forms.
* Editor autocomplete for namespace-aware refs.

!! Current limitations

* Core TiddlyWiki's backlink index and the `relink` plugin only see the
  literal `[[REF]]` string, not the resolved target. The plugin ships
  its own backlinks index (see above) that resolves correctly.
* When a tiddler with a `context:` field is transcluded from a scope
  that set `ns-context` (via pragma or widget), the outer scope wins.
  Workaround: add `\context <same-value>` at the top of the inner
  tiddler if you need it to "own" its context regardless.
