title: $:/plugins/rimir/namespace/relink-prettylink.js
type: application/javascript
module-type: relinkwikitextrule

Relink support for namespace-aware `[[…]]` / `[[text|target]]` refs.

When a tiddler T is renamed, every `[[ref]]` whose namespace resolution
points to T must be updated. We can't do a simple text-match because the
ref is usually NOT the literal title — it might be a short form that
walk-up, context, or self-prefix resolved against the source's location.

Strategy:
  1. For each match, ask the namespace resolver "what does this ref
     resolve to from this source, right now?"
  2. If the answer is fromTitle, the ref needs updating.
  3. Build a simulated post-rename wiki (fromTitle removed, toTitle added)
     and re-resolve the SAME ref text. If it still resolves to toTitle
     — meaning the user's short form remains valid even though the
     target moved — leave the ref alone.
  4. Try to find the SHORTEST suffix of toTitle that resolves to toTitle
     from the source post-rename. e.g. rename `a/b/c/d` → `a/b/c/e`
     from source `a/b/c`: try `e` first (resolves via self-prefix),
     then `c/e`, then full title. First valid form wins.
  5. Style preservation:
       - `[[oldFullTitle]]`           → `[[newFullTitle]]`
       - `[[shortRef]]` + short works → `[[newShortRef]]`
       - `[[shortRef]]` + only abs    → `[[shortRef|newFullTitle]]`
       - `[[label|target]]` keeps label, replaces target similarly

Batch renames (e.g. relink-titles cascading `knowledge/llm` → `knowledge/ai`):
each child rename runs this rule independently. Smart shortening
also helps here — `[[bar]]` from `knowledge/llm/foo` becomes `[[ai/bar]]`
when `knowledge/llm/bar` → `knowledge/ai/bar` (walk-up post-rename
catches the new title via the `knowledge` ancestor).

\*/

"use strict";

var resolver = require("$:/plugins/rimir/namespace/resolver.js");
var flags = require("$:/plugins/rimir/namespace/featureflags.js");

/* ---------- helpers ---------- */

/*
Extract a context prefix that the resolver should use when resolving refs
from sourceTitle. Mirrors the logic in filter.js's getContext() but
without access to a widget variable — we read only the persisted forms:
  1. The "context" field on the source tiddler (when implicit-context
     feature flag is on).
  2. A `\context <prefix>` pragma at the top of the source's text.
*/
function getContextForSource(sourceTitle, wiki) {
	if(!sourceTitle || !wiki) { return ""; }
	var t = wiki.getTiddler(sourceTitle);
	if(!t || !t.fields) { return ""; }
	// Pragma takes precedence over field (matches the rendering-time rule).
	var text = t.fields.text || "";
	var m = text.match(/^[ \t]*\\context[ \t]+(\S[^\r\n]*)/m);
	if(m) { return m[1].trim(); }
	if(flags.isEnabled("implicit-context", wiki) && t.fields.context) {
		return t.fields.context;
	}
	return "";
}

/*
Wrap a wiki so that fromTitle "no longer exists" and toTitle "now exists".
Used to evaluate the resolver against the post-rename state.
*/
function wrapWikiForRename(wiki, fromTitle, toTitle) {
	var sim = Object.create(wiki);
	sim.tiddlerExists = function(title) {
		if(title === fromTitle) { return false; }
		if(title === toTitle) { return true; }
		return wiki.tiddlerExists(title);
	};
	if(typeof wiki.isShadowTiddler === "function") {
		sim.isShadowTiddler = function(title) {
			if(title === fromTitle) { return false; }
			return wiki.isShadowTiddler(title);
		};
	}
	return sim;
}

/*
Wrap a wiki so that fromTitle is treated as existing, regardless of its
actual state. Needed because relink's bulkops calls deleteTiddler(from)
BEFORE the nested relinkTiddler runs, so by the time our rule fires for
a cascaded child rename the original fromTitle is already gone — the
resolver can't reach what was the ref's target. With this wrap,
"current" resolution sees the world as it was just before the rename.
*/
function wrapWikiForPreRename(wiki, fromTitle) {
	var sim = Object.create(wiki);
	sim.tiddlerExists = function(title) {
		if(title === fromTitle) { return true; }
		return wiki.tiddlerExists(title);
	};
	if(typeof wiki.isShadowTiddler === "function") {
		sim.isShadowTiddler = function(title) {
			return wiki.isShadowTiddler(title);
		};
	}
	return sim;
}

function isExternal(ref) {
	return $tw.utils.isLinkExternal(ref);
}

/*
Pick a suffix of `toTitle` (split on `/`) that resolves back to `toTitle`
from `sourceTitle` against the post-rename `simWiki`. Returns the
candidate string, or null if only the full title works.

Selection policy:
  1. Try the SAME number of segments as the original ref first.
     This preserves the user's chosen "depth" — e.g. `[[b/c/d]]` (3 segs)
     stays a 3-segment form like `[[f/c/d]]` even when a 1-segment form
     `[[d]]` would also resolve.
  2. Otherwise try shortest-first from 1 up to (segs.length - 1).
  3. Full title is excluded — caller pins absolute as fallback.

System-namespace targets ($:/...) skip this entirely; absolute is the
only safe form for them.
*/
function findGoodSelfRef(toTitle, sourceTitle, simWiki, options, originalSegCount) {
	if(!toTitle || toTitle.indexOf("$:/") === 0) { return null; }
	var segs = toTitle.split("/");
	var maxI = segs.length - 1;
	if(maxI < 1) { return null; }
	function tryAt(i) {
		var candidate = segs.slice(segs.length - i).join("/");
		if(!candidate) { return null; }
		var r = resolver.resolve(candidate, sourceTitle, simWiki, options);
		if(r.resolved === toTitle) { return candidate; }
		return null;
	}
	// 1. Same length as the original ref (when in range).
	if(originalSegCount && originalSegCount >= 1 && originalSegCount <= maxI) {
		var same = tryAt(originalSegCount);
		if(same) { return same; }
	}
	// 2. Shortest-first fallback.
	for(var i = 1; i <= maxI; i++) {
		if(i === originalSegCount) { continue; }
		var hit = tryAt(i);
		if(hit) { return hit; }
	}
	return null;
}

/* ---------- relinkwikitextrule API ---------- */

exports.name = "namespaceprettylink";

/*
Indexer pass: report every `[[ref]]` and the title it currently resolves
to. Relink uses this to know which sources contain references to which
targets, so it can call exports.relink only on the right candidates.

Critical: must advance `this.parser.pos` past the match, otherwise the
relink wikitext walker loops forever on the same match (same convention
as flibbles' built-in prettylink relinker).

Source title comes from `options.settings.title` — relink wraps each
tiddler being scanned in a TiddlerContext whose `.title` is the source.
*/
exports.report = function(text, callback, options) {
	try {
		var rawDisplay = this.match[1];
		var rawTarget  = this.match[2];
		var ref = (rawTarget !== undefined ? rawTarget : rawDisplay);
		if(!ref || isExternal(ref)) { return; }
		var sourceTitle = options.settings && options.settings.title;
		var wiki = options.wiki;
		if(!sourceTitle || !wiki) {
			// Fall back to a literal-text report so a rename of a tiddler
			// whose exact title appears in the ref still triggers our relink.
			callback(ref, "[[" + ref + "]]");
			return;
		}
		var context = getContextForSource(sourceTitle, wiki);
		var result = resolver.resolve(ref, sourceTitle, wiki, {context: context});
		if(result.resolved) {
			callback(result.resolved, "[[" + ref + "]]");
		}
	} finally {
		this.parser.pos = this.matchRegExp.lastIndex;
	}
};

/*
Rename pass: rewrite refs whose current resolution matches fromTitle.
Returns {output: "<new text>"} or undefined to leave unchanged.
*/
exports.relink = function(text, fromTitle, toTitle, options) {
	var entry;
	try {
		var rawDisplay = this.match[1];
		var rawTarget  = this.match[2];
		var ref = (rawTarget !== undefined ? rawTarget : rawDisplay);
		if(!ref || isExternal(ref)) { return undefined; }
		var sourceTitle = options.settings && options.settings.title;
		var wiki = options.wiki;
		if(!sourceTitle || !wiki) { return undefined; }
		var context = getContextForSource(sourceTitle, wiki);
		var refSegCount = ref.split("/").length;

		// Does this ref currently point to the renamed tiddler?
		// Use a pre-rename wiki so cascaded child renames (where bulkops
		// already deleted the old fromTitle before the nested relinkTiddler
		// fires) still see the original target.
		var preWiki = wrapWikiForPreRename(wiki, fromTitle);
		var current = resolver.resolve(ref, sourceTitle, preWiki, {context: context});
		if(current.resolved !== fromTitle) { return undefined; }

		// Will the same ref still resolve to toTitle after the rename?
		var simWiki = wrapWikiForRename(wiki, fromTitle, toTitle);
		var afterSame = resolver.resolve(ref, sourceTitle, simWiki, {context: context});

		var newText;
		if(rawTarget !== undefined) {
			// `[[label|target]]` — keep label, replace target.
			if(afterSame.resolved === toTitle) { return undefined; }
			var newTarget;
			if(rawTarget === fromTitle) {
				// User wrote the full title explicitly — keep absolute style.
				newTarget = toTitle;
			} else {
				// Smart-replace the target portion; fall back to absolute.
				var targetSegCount = rawTarget.split("/").length;
				newTarget = findGoodSelfRef(toTitle, sourceTitle, simWiki, {context: context}, targetSegCount) || toTitle;
			}
			newText = "[[" + rawDisplay + "|" + newTarget + "]]";
		} else if(ref === fromTitle) {
			// Absolute literal — rewrite to new absolute literal.
			newText = "[[" + toTitle + "]]";
		} else if(afterSame.resolved === toTitle) {
			// Short ref still resolves correctly — leave alone.
			return undefined;
		} else {
			// Try to find a new short form that resolves post-rename,
			// preferring the same segment count as the original ref. If
			// found, use it as both display and target. Else preserve the
			// original display text via a labeled absolute pin.
			var shortRef = findGoodSelfRef(toTitle, sourceTitle, simWiki, {context: context}, refSegCount);
			if(shortRef) {
				if(shortRef === ref) { return undefined; }
				newText = "[[" + shortRef + "]]";
			} else {
				newText = "[[" + ref + "|" + toTitle + "]]";
			}
		}
		entry = {output: newText};
	} finally {
		this.parser.pos = this.matchRegExp.lastIndex;
	}
	return entry;
};
","type":"application/javascript","module-type":"relinkwikitextrule"},"$:/plugins/rimir/namespace/resolver.js":{"title":"$:/plugins/rimir/namespace/resolver.js","text":"/*\
title: $:/plugins/rimir/namespace/resolver.js
type: application/javascript
module-type: library

Pure resolver for namespace-aware link references.

Resolution pipeline for a reference REF looked up from source tiddler SRC:

  1. Literal on raw  — REF as typed exists as-is. A real tiddler always
                      beats an alias/mount to avoid silent redirection.
  2. Alias rewrite  — [optional] exact or pattern alias rewrites REF.
                      Chained up to 3 hops for cycle safety.
  3. Mount rewrite  — `$:/tags/NamespaceMount` with `from` / `to` fields.
                      Strict prefix match; longest `from` wins. One-pass.
  4. Expand pseudos — [optional] any segment beginning with "_" is looked
                      up in the pseudo-registry (module-type: rimir-ns-pseudo).
  5. Literal on expanded — catches aliased/mounted/pseudo-expanded forms.
  6. Context prefix — if options.context is set (from \context pragma or
                      <$context> widget), try "<context>/REF" before walk-up.
                      Applies whether or not REF contains '/'.
  7. Self-prefix    — [optional] try "<sourceTitle>/REF" before walk-up.
                      Resolves descendant refs in deep namespaces without
                      per-tiddler bookkeeping. Walk-up never tries this
                      candidate (it walks up parents, not down children).
  8. Walk-up        — [optional] walk prefixes of SRC and try
                      "<prefix>/REF" at each depth. First hit wins.
                      Applies whether or not REF contains '/' — a multi-
                      segment REF like "test/sum" can still resolve via
                      ancestor prefixes (e.g. source "a/b/c" + REF "c/X"
                      → "a/b/c/X" then "a/b/X" then "a/X").
  9. Unresolved     — no candidate matched.

System-namespace refs ($:/...) short-circuit to unresolved before
context+walk-up to avoid degenerate matches like "$:/REF".

Stages marked [optional] are gated by feature flags (see featureflags.js).
All four optional features default to OFF; users enable them in the
plugin's settings tab.

Pseudo-segments are pluggable: each resolver is its own JS module with
module-type `rimir-ns-pseudo`, exporting `name` (the full segment string
including leading underscore) and `resolve(prefix, wiki)`. See
`pseudo/_latest.js` for the reference implementation.

Pseudo lookups are cached per-wiki, keyed by (pseudoName, prefix). The
companion startup module walks every changed title's ancestor prefixes
and drops matching cache entries.

\*/

"use strict";

/* ---------- path helpers ---------- */

/*
Split a tiddler title into path segments on '/'. System titles ('$:/…')
keep "$:" as the first segment so walk-up can traverse within the system
namespace — enabling shadow-tiddler demos and plugin-internal links.
Walk-up stops at i>=2 for $:/ titles to avoid degenerate "$:/REF"
candidates that would match nothing useful.
*/
exports.splitPath = function(title) {
	if(!title) { return []; }
	if(title.indexOf("$:/") === 0) {
		var rest = title.substring(3);
		return rest ? ["$:"].concat(rest.split("/")) : ["$:"];
	}
	return title.split("/");
};

/*
Check whether a tiddler exists as a regular OR shadow tiddler. Shadow
tiddlers (from plugins like $:/core) must count as "resolved" or every
[[$:/ControlPanel]]-style link would be flagged unresolved.
*/
function exists(wiki, title) {
	return wiki.tiddlerExists(title) || (wiki.isShadowTiddler && wiki.isShadowTiddler(title));
}

/* ---------- utility for pseudo-resolvers ---------- */

/*
Return the set of immediate child segments under a given prefix, across
both regular and shadow tiddlers. Empty-string segments (trailing slashes)
are dropped.

This is the one enumeration primitive pseudo-resolvers should need: give
me what's directly below `<prefix>/`, filter/sort it however you like,
return one segment.
*/
exports.listImmediateChildren = function(prefix, wiki) {
	var children = Object.create(null),
		pfx = prefix + "/";
	function collect(tiddler, title) {
		if(title.indexOf(pfx) !== 0) { return; }
		var rest = title.substring(pfx.length),
			slashAt = rest.indexOf("/"),
			seg = slashAt === -1 ? rest : rest.substring(0, slashAt);
		if(seg) { children[seg] = true; }
	}
	if(wiki.each) { wiki.each(collect); }
	if(wiki.eachShadow) { wiki.eachShadow(collect); }
	return Object.keys(children);
};

/* ---------- pseudo-segment registry ---------- */

// Cached registry map: pseudoName → resolve(prefix, wiki)
var registry = null;

function getRegistry() {
	if(registry !== null) { return registry; }
	registry = Object.create(null);
	if($tw && $tw.modules && $tw.modules.getModulesByTypeAsHashmap) {
		var mods = $tw.modules.getModulesByTypeAsHashmap("rimir-ns-pseudo");
		for(var key in mods) {
			var mod = mods[key];
			if(mod && typeof mod.name === "string" && typeof mod.resolve === "function") {
				registry[mod.name] = mod.resolve;
			}
		}
	}
	return registry;
}

/*
Reset the registry. Useful if pseudo modules are added/removed at runtime
(rare — mostly for tests). Normal operation builds the registry once at
first use and keeps it.
*/
exports.resetPseudoRegistry = function() {
	registry = null;
};

/* ---------- pseudo result cache ---------- */

// WeakMap<wiki, Map<"<pseudoName>\x1f<prefix>", string|null>>
var caches = typeof WeakMap !== "undefined" ? new WeakMap() : null;
var CACHE_SEP = "\x1f";

function getCache(wiki) {
	if(!caches) { return null; }
	var c = caches.get(wiki);
	if(!c) {
		c = new Map();
		caches.set(wiki, c);
	}
	return c;
}

function cacheKey(pseudoName, prefix) {
	return pseudoName + CACHE_SEP + prefix;
}

/*
Drop cached pseudo results.
  * With no wiki — drop every wiki's cache wholesale (useful in tests).
  * With wiki, no prefix — drop all entries for that wiki.
  * With wiki + prefix — drop only entries matching the prefix, across
    all pseudo names.
*/
exports.invalidatePseudoCache = function(prefix, wiki) {
	if(!caches) { return; }
	if(!wiki) {
		caches = typeof WeakMap !== "undefined" ? new WeakMap() : null;
		return;
	}
	var cache = caches.get(wiki);
	if(!cache) { return; }
	if(!prefix) {
		cache.clear();
		return;
	}
	var toDelete = [];
	cache.forEach(function(_value, key) {
		var sep = key.indexOf(CACHE_SEP);
		if(sep !== -1 && key.substring(sep + 1) === prefix) {
			toDelete.push(key);
		}
	});
	for(var i = 0; i < toDelete.length; i++) { cache.delete(toDelete[i]); }
};

function resolvePseudo(pseudoName, prefix, wiki) {
	var cache = getCache(wiki),
		key = cacheKey(pseudoName, prefix);
	if(cache && cache.has(key)) { return cache.get(key); }
	var fn = getRegistry()[pseudoName];
	if(!fn) { return undefined; }  // not a known pseudo — let caller leave segment as literal
	var result;
	try {
		result = fn(prefix, wiki);
	} catch(e) {
		console.error("namespace pseudo '" + pseudoName + "' threw:", e);
		result = null;
	}
	if(typeof result !== "string") { result = null; }
	if(cache) { cache.set(key, result); }
	return result;
}

/*
Expand every pseudo-segment (any segment starting with "_") in the ref
against its preceding prefix. Returns the expanded ref, or null if any
pseudo resolver returned null. Unknown _-prefixed segments are left
untouched (treated as literal — lets users have tiddlers legitimately
named `_something` without triggering the pipeline).
*/
exports.expandPseudoSegments = function(ref, wiki) {
	if(ref.indexOf("_") === -1) { return ref; }
	var segs = ref.split("/"),
		changed = false;
	for(var i = 0; i < segs.length; i++) {
		if(segs[i].charAt(0) !== "_") { continue; }
		var prefix = segs.slice(0, i).join("/"),
			replacement = resolvePseudo(segs[i], prefix, wiki);
		if(replacement === undefined) { continue; }  // unknown pseudo — leave as literal
		if(replacement === null) { return null; }    // known pseudo, couldn't resolve
		segs[i] = replacement;
		changed = true;
	}
	return changed ? segs.join("/") : ref;
};

/* ---------- main resolver ---------- */

var aliases = require("$:/plugins/rimir/namespace/aliases.js");
var mounts  = require("$:/plugins/rimir/namespace/mounts.js");
var flags   = require("$:/plugins/rimir/namespace/featureflags.js");

var ALIAS_MAX_HOPS = 3;

/*
Resolve a reference.

ref:         the raw link target as the user typed it (e.g. "V3.3",
             "OWASP/ASVS/_latest/V3.3", "NS_V3.3")
sourceTitle: title of the tiddler being rendered
wiki:        $tw.wiki (needs tiddlerExists, isShadowTiddler, each, eachShadow)
options:     optional; {context: "<prefix>"} to supply a declared context
             that shadows walk-up. Pseudo-segments in the context prefix
             are expanded before use.

Returns: {status, resolved, tried}
  status:   "literal" | "alias" | "mount" | "absolute" | "context" |
            "self" | "walkup" | "unresolved"
  resolved: resolved title or null
  tried:    ordered array of every title we checked (useful for tooltips)
*/
exports.resolve = function(ref, sourceTitle, wiki, options) {
	options = options || {};
	var tried = [];
	if(!ref) {
		return {status: "unresolved", resolved: null, tried: tried};
	}
	// 1. Literal on raw ref — a real tiddler always beats an alias/mount.
	tried.push(ref);
	if(exists(wiki, ref)) {
		return {status: "literal", resolved: ref, tried: tried};
	}
	// 2. Alias rewrite — chain up to ALIAS_MAX_HOPS hops for cycle safety.
	//    Gated by the "aliases" feature flag.
	var rewritten = ref;
	var wasAliased = false;
	if(flags.isEnabled("aliases", wiki)) {
		for(var d = 0; d < ALIAS_MAX_HOPS; d++) {
			var next = aliases.resolveAlias(rewritten, wiki);
			if(!next || next === rewritten) { break; }
			rewritten = next;
		}
		wasAliased = (rewritten !== ref);
		if(wasAliased) { tried.push(rewritten); }
	}
	// 3. Mount rewrite — single pass, longest `from` wins.
	var mounted = mounts.resolveMount(rewritten, wiki);
	if(mounted && mounted !== rewritten) {
		rewritten = mounted;
		tried.push(rewritten);
	}
	var wasMounted = (mounted != null);
	// 4. Expand pseudo-segments on the (possibly rewritten) ref.
	//    Gated by the "pseudo-expansion" feature flag.
	var expanded = rewritten;
	if(flags.isEnabled("pseudo-expansion", wiki)) {
		expanded = exports.expandPseudoSegments(rewritten, wiki);
		if(expanded === null) {
			return {status: "unresolved", resolved: null, tried: tried};
		}
		if(expanded !== rewritten) { tried.push(expanded); }
	}
	// 5. Literal on expanded — catches "ref was aliased/mounted and/or
	//    pseudo-expanded to a real title".
	if(expanded !== ref && exists(wiki, expanded)) {
		var status = wasMounted ? "mount" : (wasAliased ? "alias" : "literal");
		return {status: status, resolved: expanded, tried: tried};
	}
	// System-namespace refs never walk up or use context — anything
	// starting with $:/ is treated as absolute.
	if(expanded.indexOf("$:/") === 0) {
		return {status: "unresolved", resolved: null, tried: tried};
	}
	// 6. Context prefix — try "<context>/REF" when a declared context is
	//    present. Pseudo-segments in the context string expand too, so
	//    e.g. `\context OWASP/ASVS/_latest` drifts with the newest version.
	if(options.context) {
		var ctx = flags.isEnabled("pseudo-expansion", wiki)
			? exports.expandPseudoSegments(options.context, wiki)
			: options.context;
		if(ctx !== null && ctx !== "") {
			var ctxCandidate = ctx + "/" + expanded;
			tried.push(ctxCandidate);
			if(exists(wiki, ctxCandidate)) {
				return {status: "context", resolved: ctxCandidate, tried: tried};
			}
		}
	}
	// 7. Self-prefix — try "<sourceTitle>/REF" when the feature is on.
	//    Catches descendant refs (e.g. source "a/b/c" + REF "x/y"
	//    → "a/b/c/x/y") that walk-up would miss because walk-up only
	//    considers ancestor prefixes.
	if(sourceTitle && flags.isEnabled("self-prefix", wiki)) {
		var selfCandidate = sourceTitle + "/" + expanded;
		tried.push(selfCandidate);
		if(exists(wiki, selfCandidate)) {
			return {status: "self", resolved: selfCandidate, tried: tried};
		}
	}
	// 8. Walk-up from the source tiddler's prefix.
	//    Gated by the "walk-up" feature flag.
	if(sourceTitle && flags.isEnabled("walk-up", wiki)) {
		var segs = exports.splitPath(sourceTitle);
		// For $:/ titles the first segment is the "$:" marker; stop at i=2
		// so the shallowest prefix is "$:/<first-real-seg>" rather than
		// a bare "$:/REF".
		var minI = (segs[0] === "$:") ? 2 : 1;
		// Walk up to minI (inclusive). i = 0 would be the bare ref, already
		// tried as literal.
		for(var i = segs.length - 1; i >= minI; i--) {
			var candidate = segs.slice(0, i).join("/") + "/" + expanded;
			tried.push(candidate);
			if(exists(wiki, candidate)) {
				return {status: "walkup", resolved: candidate, tried: tried};
			}
		}
	}
	return {status: "unresolved", resolved: null, tried: tried};
};
