title: $:/plugins/rimir/namespace/test/test-aliases.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the aliases module — exact and pattern forms, precedence,
malformed entries, and chained rewrites.

\*/

"use strict";

describe("namespace: aliases", function() {

	var aliases = require("$:/plugins/rimir/namespace/aliases.js");
	var resolver = require("$:/plugins/rimir/namespace/resolver.js");
	var flags = require("$:/plugins/rimir/namespace/featureflags.js");

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		wiki.addTiddler({title: "$:/config/rimir/namespace/aliases", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/pseudo-expansion", text: "yes"});
		wiki.addIndexersToWiki();
		return wiki;
	}

	beforeEach(function() {
		flags.invalidate();
		aliases.invalidateAliases();
		resolver.invalidatePseudoCache();
	});

	describe("exact aliases", function() {

		it("rewrites when short matches", function() {
			var wiki = setupWiki([
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "X", "expands-to": "a/b/c"}
			]);
			expect(aliases.resolveAlias("X", wiki)).toBe("a/b/c");
		});

		it("returns null when short doesn't match", function() {
			var wiki = setupWiki([
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "X", "expands-to": "y"}
			]);
			expect(aliases.resolveAlias("Y", wiki)).toBeNull();
		});

		it("ignores entries missing required fields", function() {
			var wiki = setupWiki([
				{title: "$:/a1", tags: "$:/tags/NamespaceAlias", "short": "", "expands-to": "y"},
				{title: "$:/a2", tags: "$:/tags/NamespaceAlias", "short": "X", "expands-to": ""},
				{title: "$:/a3", tags: "$:/tags/NamespaceAlias", "short": "OK", "expands-to": "target"}
			]);
			expect(aliases.resolveAlias("X", wiki)).toBeNull();
			expect(aliases.resolveAlias("", wiki)).toBeNull();
			expect(aliases.resolveAlias("OK", wiki)).toBe("target");
		});

	});

	describe("pattern aliases", function() {

		it("rewrites via regex substitution", function() {
			var wiki = setupWiki([
				{title: "$:/p", tags: "$:/tags/NamespacePatternAlias", pattern: "^V_(.+)$", replacement: "vers/$1"}
			]);
			expect(aliases.resolveAlias("V_abc", wiki)).toBe("vers/abc");
		});

		it("doesn't match when regex fails", function() {
			var wiki = setupWiki([
				{title: "$:/p", tags: "$:/tags/NamespacePatternAlias", pattern: "^V_(.+)$", replacement: "vers/$1"}
			]);
			expect(aliases.resolveAlias("something-else", wiki)).toBeNull();
		});

		it("supports multiple capture groups", function() {
			var wiki = setupWiki([
				{title: "$:/p", tags: "$:/tags/NamespacePatternAlias", pattern: "^(\\w+)/(\\w+)$", replacement: "$2/$1"}
			]);
			expect(aliases.resolveAlias("foo/bar", wiki)).toBe("bar/foo");
		});

		it("skips invalid regex (and logs)", function() {
			// Spy on console.error to verify warning, then ensure a sibling
			// valid pattern still works.
			var errSpy = spyOn(console, "error");
			var wiki = setupWiki([
				{title: "$:/bad", tags: "$:/tags/NamespacePatternAlias", pattern: "[unclosed", replacement: "x"},
				{title: "$:/ok", tags: "$:/tags/NamespacePatternAlias", pattern: "^OK$", replacement: "fine"}
			]);
			expect(aliases.resolveAlias("OK", wiki)).toBe("fine");
			expect(errSpy).toHaveBeenCalled();
		});

	});

	describe("precedence: exact > pattern", function() {

		it("exact alias wins when both match the same ref", function() {
			var wiki = setupWiki([
				{title: "$:/ex", tags: "$:/tags/NamespaceAlias", "short": "X", "expands-to": "winner"},
				{title: "$:/pat", tags: "$:/tags/NamespacePatternAlias", pattern: "^X$", replacement: "loser"}
			]);
			expect(aliases.resolveAlias("X", wiki)).toBe("winner");
		});

	});

	describe("chained aliases via resolve()", function() {

		it("applies up to 3 hops, then stops", function() {
			// a → b → c → d → e, but only 3 hops allowed
			var wiki = setupWiki([
				{title: "e", text: ""},
				{title: "$:/1", tags: "$:/tags/NamespaceAlias", "short": "a", "expands-to": "b"},
				{title: "$:/2", tags: "$:/tags/NamespaceAlias", "short": "b", "expands-to": "c"},
				{title: "$:/3", tags: "$:/tags/NamespaceAlias", "short": "c", "expands-to": "d"},
				{title: "$:/4", tags: "$:/tags/NamespaceAlias", "short": "d", "expands-to": "e"}
			]);
			// 3 hops: a → b → c → d. Since "d" doesn't exist literally, walk-up
			// won't find it either, so it's unresolved (we stopped before
			// hopping to "e" which does exist).
			var r = resolver.resolve("a", null, wiki);
			expect(r.status).toBe("unresolved");
		});

		it("handles direct cycles gracefully", function() {
			var wiki = setupWiki([
				{title: "$:/a1", tags: "$:/tags/NamespaceAlias", "short": "A", "expands-to": "B"},
				{title: "$:/a2", tags: "$:/tags/NamespaceAlias", "short": "B", "expands-to": "A"}
			]);
			// No infinite loop — capped at 3 hops and terminates cleanly.
			expect(function() {
				resolver.resolve("A", null, wiki);
			}).not.toThrow();
		});

	});

	describe("aliases interact with pseudo expansion", function() {

		it("alias expansion containing _latest still drifts", function() {
			var wiki = setupWiki([
				{title: "v/3.0/x", text: ""},
				{title: "v/4.0/x", text: ""},
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "SHORT", "expands-to": "v/_latest/x"}
			]);
			var r = resolver.resolve("SHORT", null, wiki);
			expect(r.status).toBe("alias");
			expect(r.resolved).toBe("v/4.0/x");
		});

	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-context-and-filter.js":{"title":"$:/plugins/rimir/namespace/test/test-context-and-filter.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-context-and-filter.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the $context widget and the ns-resolve / ns-resolve-class
filter operators — covers the seam where the resolver pipeline meets
wikitext. In particular: that `ns-context` widget variable wins over
the tiddler's `context` field, and that an unresolved ref still gets a
sensible `to` (= the original ref) so the link remains clickable.

\*/

"use strict";

describe("namespace: $context widget", function() {

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		wiki.addIndexersToWiki();
		return wiki;
	}

	// Render a tiddler body and return the resulting DOM text. We use
	// <$text text=<<ns-context>>/> as a sentinel so we can directly
	// assert the variable was set in the right scope.
	function renderText(wiki, body) {
		wiki.addTiddler({title: "renderme", text: body});
		var widget = wiki.makeTranscludeWidget("renderme",
			{parseAsInline: false, document: $tw.fakeDocument});
		var container = $tw.fakeDocument.createElement("div");
		widget.render(container, null);
		return container.textContent;
	}

	it("$context widget sets ns-context for its children", function() {
		var wiki = setupWiki();
		var text = renderText(wiki,
			"<$context prefix=\"foo/bar\">\n\n<$text text=<<ns-context>>/>\n\n</$context>");
		expect(text).toContain("foo/bar");
	});

	it("\\context pragma sets ns-context for the rest of the body", function() {
		var wiki = setupWiki();
		var text = renderText(wiki, "\\context my/ctx\n\n<$text text=<<ns-context>>/>");
		expect(text).toContain("my/ctx");
	});

	it("ns-context is empty/undefined outside any $context scope", function() {
		var wiki = setupWiki();
		var text = renderText(wiki, "<$text text=<<ns-context>>/>");
		// No context set — sentinel renders empty.
		expect(text.trim()).toBe("");
	});

});

describe("namespace: ns-resolve filter operator", function() {

	var aliases = require("$:/plugins/rimir/namespace/aliases.js"),
		mounts = require("$:/plugins/rimir/namespace/mounts.js"),
		resolver = require("$:/plugins/rimir/namespace/resolver.js"),
		flags = require("$:/plugins/rimir/namespace/featureflags.js");

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		wiki.addTiddler({title: "$:/config/rimir/namespace/walk-up", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/aliases", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/implicit-context", text: "yes"});
		wiki.addIndexersToWiki();
		return wiki;
	}

	beforeEach(function() {
		flags.invalidate();
		resolver.invalidatePseudoCache();
		aliases.invalidateAliases();
		mounts.invalidateMounts();
	});

	describe("ns-resolve", function() {

		it("returns the resolved title when literal hits", function() {
			var wiki = setupWiki([{title: "Foo", text: ""}]);
			var r = wiki.filterTiddlers("[[Foo]ns-resolve[]]");
			expect(r).toEqual(["Foo"]);
		});

		it("returns the original ref when unresolved (so $link still works)", function() {
			var wiki = setupWiki([]);
			var r = wiki.filterTiddlers("[[Missing]ns-resolve[]]");
			expect(r).toEqual(["Missing"]);
		});

		it("uses source-tiddler operand for walk-up", function() {
			var wiki = setupWiki([{title: "a/b/X", text: ""}]);
			var r = wiki.filterTiddlers("[[X]ns-resolve[a/b/source]]");
			expect(r).toEqual(["a/b/X"]);
		});

		it("uses context field on the source tiddler as fallback", function() {
			var wiki = setupWiki([
				{title: "ctx/X", text: ""},
				{title: "src", text: "", context: "ctx"}
			]);
			var r = wiki.filterTiddlers("[[X]ns-resolve[src]]");
			expect(r).toEqual(["ctx/X"]);
		});

		it("widget variable ns-context wins over context field", function() {
			// End-to-end: a body that calls ns-resolve from inside a
			// $context wrapper. The wrapper sets ns-context="winner"; the
			// source tiddler also has a context field "loser". The widget
			// variable must take precedence.
			var wiki = setupWiki([
				{title: "winner/X", text: ""},
				{title: "loser/X", text: ""},
				{title: "src", text: "", context: "loser"}
			]);
			wiki.addTiddler({
				title: "renderme",
				text: "<$context prefix=\"winner\">\n\n" +
					"<$text text={{{ [[X]ns-resolve[src]] }}}/>\n\n" +
					"</$context>"
			});
			var widget = wiki.makeTranscludeWidget("renderme",
				{parseAsInline: false, document: $tw.fakeDocument});
			var container = $tw.fakeDocument.createElement("div");
			widget.render(container, null);
			expect(container.textContent).toContain("winner/X");
		});

	});

	describe("ns-resolve-class", function() {

		it("returns ns-resolved class when ref resolves", function() {
			var wiki = setupWiki([{title: "Foo", text: ""}]);
			var r = wiki.filterTiddlers("[[Foo]ns-resolve-class[]]");
			expect(r).toEqual(["tc-tiddlylink ns-resolved"]);
		});

		it("returns ns-unresolved class when ref doesn't resolve", function() {
			var wiki = setupWiki([]);
			var r = wiki.filterTiddlers("[[Missing]ns-resolve-class[]]");
			expect(r).toEqual(["tc-tiddlylink ns-unresolved"]);
		});

		it("ns-resolved when alias rewrites", function() {
			var wiki = setupWiki([
				{title: "real", text: ""},
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "ALI", "expands-to": "real"}
			]);
			var r = wiki.filterTiddlers("[[ALI]ns-resolve-class[]]");
			expect(r).toEqual(["tc-tiddlylink ns-resolved"]);
		});

		it("ns-resolved when walk-up succeeds", function() {
			var wiki = setupWiki([{title: "a/b/X", text: ""}]);
			var r = wiki.filterTiddlers("[[X]ns-resolve-class[a/b/src]]");
			expect(r).toEqual(["tc-tiddlylink ns-resolved"]);
		});

	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-featureflags.js":{"title":"$:/plugins/rimir/namespace/test/test-featureflags.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-featureflags.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the feature flags module — verifies that optional resolver
stages (walk-up, aliases, pseudo-expansion, implicit-context) are
properly gated by their config tiddlers.

\*/

"use strict";

describe("namespace: featureflags", function() {

	var flags = require("$:/plugins/rimir/namespace/featureflags.js");
	var resolver = require("$:/plugins/rimir/namespace/resolver.js");
	var aliases = require("$:/plugins/rimir/namespace/aliases.js");
	var mounts = require("$:/plugins/rimir/namespace/mounts.js");
	var indexer = require("$:/plugins/rimir/namespace/indexer.js");

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		wiki.addIndexersToWiki();
		return wiki;
	}

	function enableFlag(wiki, name) {
		wiki.addTiddler({title: "$:/config/rimir/namespace/" + name, text: "yes"});
		flags.invalidate();
	}

	beforeEach(function() {
		flags.invalidate();
		resolver.invalidatePseudoCache();
		aliases.invalidateAliases();
		mounts.invalidateMounts();
		indexer.reset();
	});

	describe("flag defaults", function() {

		it("all flags return false when config tiddlers don't exist", function() {
			var wiki = setupWiki([]);
			expect(flags.isEnabled("walk-up", wiki)).toBe(false);
			expect(flags.isEnabled("implicit-context", wiki)).toBe(false);
			expect(flags.isEnabled("pseudo-expansion", wiki)).toBe(false);
			expect(flags.isEnabled("aliases", wiki)).toBe(false);
		});

		it("all flags return false when config tiddlers contain 'no'", function() {
			var wiki = setupWiki([
				{title: "$:/config/rimir/namespace/walk-up", text: "no"},
				{title: "$:/config/rimir/namespace/implicit-context", text: "no"},
				{title: "$:/config/rimir/namespace/pseudo-expansion", text: "no"},
				{title: "$:/config/rimir/namespace/aliases", text: "no"}
			]);
			expect(flags.isEnabled("walk-up", wiki)).toBe(false);
			expect(flags.isEnabled("aliases", wiki)).toBe(false);
		});

		it("returns true when config tiddler contains 'yes'", function() {
			var wiki = setupWiki([
				{title: "$:/config/rimir/namespace/walk-up", text: "yes"}
			]);
			expect(flags.isEnabled("walk-up", wiki)).toBe(true);
		});

		it("handles whitespace and case variations", function() {
			var wiki = setupWiki([
				{title: "$:/config/rimir/namespace/walk-up", text: " Yes "},
				{title: "$:/config/rimir/namespace/aliases", text: "YES"}
			]);
			expect(flags.isEnabled("walk-up", wiki)).toBe(true);
			expect(flags.isEnabled("aliases", wiki)).toBe(true);
		});

		it("invalidate() causes re-read on next call", function() {
			var wiki = setupWiki([]);
			expect(flags.isEnabled("walk-up", wiki)).toBe(false);
			wiki.addTiddler({title: "$:/config/rimir/namespace/walk-up", text: "yes"});
			flags.invalidate();
			expect(flags.isEnabled("walk-up", wiki)).toBe(true);
		});

	});

	describe("isConfigChange", function() {

		it("returns true when changes contain a config tiddler", function() {
			var changes = {"$:/config/rimir/namespace/walk-up": {modified: true}};
			expect(flags.isConfigChange(changes)).toBe(true);
		});

		it("returns false for unrelated changes", function() {
			var changes = {"some/tiddler": {modified: true}};
			expect(flags.isConfigChange(changes)).toBe(false);
		});

	});

	describe("walk-up gating", function() {

		it("walk-up OFF: resolve returns unresolved even when target exists in parent", function() {
			var wiki = setupWiki([{title: "a/b/X", text: ""}]);
			var r = resolver.resolve("X", "a/b/source", wiki);
			expect(r.status).toBe("unresolved");
		});

		it("walk-up ON: resolve walks up and finds target", function() {
			var wiki = setupWiki([{title: "a/b/X", text: ""}]);
			enableFlag(wiki, "walk-up");
			var r = resolver.resolve("X", "a/b/source", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/b/X");
		});

		it("walk-up OFF but context still works", function() {
			var wiki = setupWiki([{title: "ctx/X", text: ""}]);
			// No walk-up flag, but explicit context
			var r = resolver.resolve("X", "some/source", wiki, {context: "ctx"});
			expect(r.status).toBe("context");
			expect(r.resolved).toBe("ctx/X");
		});

	});

	describe("alias gating", function() {

		it("aliases OFF: alias tiddler ignored", function() {
			var wiki = setupWiki([
				{title: "real/target", text: ""},
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "SHORT", "expands-to": "real/target"}
			]);
			var r = resolver.resolve("SHORT", null, wiki);
			expect(r.status).toBe("unresolved");
		});

		it("aliases ON: alias rewrites ref", function() {
			var wiki = setupWiki([
				{title: "real/target", text: ""},
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "SHORT", "expands-to": "real/target"}
			]);
			enableFlag(wiki, "aliases");
			var r = resolver.resolve("SHORT", null, wiki);
			expect(r.status).toBe("alias");
			expect(r.resolved).toBe("real/target");
		});

	});

	describe("pseudo gating", function() {

		it("pseudos OFF: _latest treated as literal", function() {
			var wiki = setupWiki([
				{title: "v/3.0/x", text: ""},
				{title: "v/4.0/x", text: ""}
			]);
			var r = resolver.resolve("v/_latest/x", null, wiki);
			expect(r.status).toBe("unresolved");
		});

		it("pseudos ON: _latest expands to highest version", function() {
			var wiki = setupWiki([
				{title: "v/3.0/x", text: ""},
				{title: "v/4.0/x", text: ""}
			]);
			enableFlag(wiki, "pseudo-expansion");
			var r = resolver.resolve("v/_latest/x", null, wiki);
			expect(r.resolved).toBe("v/4.0/x");
		});

		it("pseudos OFF + context: context string not expanded", function() {
			var wiki = setupWiki([
				{title: "v/3.0/x", text: ""},
				{title: "v/4.0/x", text: ""}
			]);
			// _latest in context should NOT expand when pseudo flag is off
			var r = resolver.resolve("x", "source", wiki, {context: "v/_latest"});
			// tries literal "v/_latest/x" which doesn't exist
			expect(r.status).toBe("unresolved");
		});

		it("pseudos ON + context: context string expanded", function() {
			var wiki = setupWiki([
				{title: "v/3.0/x", text: ""},
				{title: "v/4.0/x", text: ""}
			]);
			enableFlag(wiki, "pseudo-expansion");
			var r = resolver.resolve("x", "source", wiki, {context: "v/_latest"});
			expect(r.status).toBe("context");
			expect(r.resolved).toBe("v/4.0/x");
		});

	});

	describe("implicit-context gating", function() {

		it("implicit-context OFF: context field ignored by filter operator", function() {
			var wiki = setupWiki([
				{title: "ctx/X", text: ""},
				{title: "src", text: "", context: "ctx"}
			]);
			enableFlag(wiki, "walk-up");
			var r = wiki.filterTiddlers("[[X]ns-resolve[src]]");
			// Without implicit-context, the field is ignored.
			// Walk-up from "src" (no /) won't find "ctx/X" either.
			expect(r).toEqual(["X"]);
		});

		it("implicit-context ON: context field used as fallback", function() {
			var wiki = setupWiki([
				{title: "ctx/X", text: ""},
				{title: "src", text: "", context: "ctx"}
			]);
			enableFlag(wiki, "implicit-context");
			var r = wiki.filterTiddlers("[[X]ns-resolve[src]]");
			expect(r).toEqual(["ctx/X"]);
		});

		it("implicit-context OFF: \\context pragma still works", function() {
			var wiki = setupWiki([{title: "ctx/X", text: ""}]);
			// Render a tiddler with \context pragma — should resolve
			// regardless of the implicit-context flag.
			wiki.addTiddler({
				title: "renderme",
				text: "\\context ctx\n\n<$text text={{{ [[X]ns-resolve[renderme]] }}}/>"
			});
			var widget = wiki.makeTranscludeWidget("renderme",
				{parseAsInline: false, document: $tw.fakeDocument});
			var container = $tw.fakeDocument.createElement("div");
			widget.render(container, null);
			expect(container.textContent).toContain("ctx/X");
		});

	});

	describe("indexer respects flags", function() {

		it("walk-up OFF: indexer does not index walk-up resolves", function() {
			var wiki = setupWiki([
				{title: "a/b/source", text: "see [[target]]"},
				{title: "a/target", text: ""}
			]);
			indexer.rebuildAll(wiki);
			// Walk-up is off, so [[target]] from a/b/source won't resolve to a/target
			expect(indexer.getBacklinks("a/target")).toEqual([]);
		});

		it("walk-up ON: indexer indexes walk-up resolves", function() {
			var wiki = setupWiki([
				{title: "a/b/source", text: "see [[target]]"},
				{title: "a/target", text: ""}
			]);
			enableFlag(wiki, "walk-up");
			indexer.rebuildAll(wiki);
			expect(indexer.getBacklinks("a/target")).toEqual(["a/b/source"]);
		});

		it("implicit-context OFF: indexer ignores context field", function() {
			var wiki = setupWiki([
				{title: "ctx/target", text: ""},
				{title: "source", context: "ctx", text: "uses [[target]]"}
			]);
			indexer.rebuildAll(wiki);
			expect(indexer.getBacklinks("ctx/target")).toEqual([]);
		});

		it("implicit-context ON: indexer uses context field", function() {
			var wiki = setupWiki([
				{title: "ctx/target", text: ""},
				{title: "source", context: "ctx", text: "uses [[target]]"}
			]);
			enableFlag(wiki, "implicit-context");
			indexer.rebuildAll(wiki);
			expect(indexer.getBacklinks("ctx/target")).toEqual(["source"]);
		});

	});

});
