title: $:/plugins/rimir/namespace/test/test-pragma.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the \context pragma rule — verifies the AST shape (a $context
node with a `prefix` attribute) and that the wikiparser auto-wraps the
remaining body as the context node's children.

\*/

"use strict";

describe("namespace: \\context pragma rule", function() {

	function parse(text) {
		var wiki = new $tw.Wiki();
		return wiki.parseText("text/vnd.tiddlywiki", text).tree;
	}

	function findContext(tree) {
		for(var i = 0; i < tree.length; i++) {
			if(tree[i].type === "context") { return tree[i]; }
		}
		return null;
	}

	it("emits a $context node with the prefix attribute", function() {
		var tree = parse("\\context OWASP/ASVS/4.0.3\n\nBody here");
		var ctx = findContext(tree);
		expect(ctx).not.toBeNull();
		expect(ctx.attributes.prefix).toEqual({
			name: "prefix",
			type: "string",
			value: "OWASP/ASVS/4.0.3"
		});
	});

	it("preserves orderedAttributes (required for some widget paths)", function() {
		var ctx = findContext(parse("\\context X/Y\n\nBody"));
		expect(ctx.orderedAttributes).toBeDefined();
		expect(ctx.orderedAttributes.length).toBe(1);
		expect(ctx.orderedAttributes[0].name).toBe("prefix");
		expect(ctx.orderedAttributes[0].value).toBe("X/Y");
	});

	it("auto-wraps subsequent body as children", function() {
		var ctx = findContext(parse("\\context ctx\n\nSome body text"));
		// Body parsed into children — the exact shape depends on the
		// inline/block rules that fire next, but it must be non-empty.
		expect(ctx.children).toBeDefined();
		expect(ctx.children.length).toBeGreaterThan(0);
	});

	it("captures the prefix verbatim — no normalisation", function() {
		var ctx = findContext(parse("\\context a/b\n"));
		expect(ctx.attributes.prefix.value).toBe("a/b");
	});

	it("only matches when at the top of the tiddler (in pragma section)", function() {
		// `\context` mid-body is plain text, not a pragma.
		var tree = parse("Some text\n\\context X\n\nMore text");
		expect(findContext(tree)).toBeNull();
	});

	it("ignores trailing whitespace on the pragma line", function() {
		var ctx = findContext(parse("\\context X/Y   \n\nBody"));
		expect(ctx).not.toBeNull();
		expect(ctx.attributes.prefix.value).toBe("X/Y");
	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-prettylink.js":{"title":"$:/plugins/rimir/namespace/test/test-prettylink.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-prettylink.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the namespace prettylink wikirule — verifies the AST shape that
[[REF]] / [[text|REF]] expands to. Guards the `$let` name-attribute fix
(LetWidget reads attribute.name from the value, not the map key) and
confirms the external-link branch is preserved verbatim.

\*/

"use strict";

describe("namespace: prettylink rule", function() {

	function parse(text) {
		var wiki = new $tw.Wiki();
		return wiki.parseText("text/vnd.tiddlywiki", text).tree;
	}

	// Skip the auto-wrapping <p> the parser adds in inline mode.
	function inline(tree) {
		var p = tree[0];
		if(p && p.type === "element" && p.tag === "p") { return p.children; }
		return tree;
	}

	describe("internal links", function() {

		it("emits a $let wrapper with __nsref__ name attribute", function() {
			var nodes = inline(parse("[[Foo]]"));
			expect(nodes.length).toBe(1);
			var letNode = nodes[0];
			expect(letNode.type).toBe("let");
			// The name-attribute fix: LetWidget reads attribute.name from
			// the value, not the map key.
			var attr = letNode.attributes["__nsref__"];
			expect(attr).toBeDefined();
			expect(attr.name).toBe("__nsref__");
			expect(attr.type).toBe("string");
			expect(attr.value).toBe("Foo");
		});

		it("wraps a $link child with filtered to/class attributes referencing __nssrc__", function() {
			var letNode = inline(parse("[[Foo]]"))[0];
			expect(letNode.children.length).toBe(1);
			var link = letNode.children[0];
			expect(link.type).toBe("link");
			expect(link.attributes.to).toEqual({
				type: "filtered",
				filter: "[<__nsref__>ns-resolve<__nssrc__>]"
			});
			expect(link.attributes["class"]).toEqual({
				type: "filtered",
				filter: "[<__nsref__>ns-resolve-class<__nssrc__>]"
			});
		});

		it("emits a __nssrc__ attribute that prefers thisTiddler over currentTiddler", function() {
			// thisTiddler is set by $transclude (TW 5.4.0+), currentTiddler
			// by the $tiddler widget. The let's __nssrc__ must pick whichever
			// is set so walk-up has a non-empty source title.
			var letNode = inline(parse("[[Foo]]"))[0];
			var attr = letNode.attributes["__nssrc__"];
			expect(attr).toBeDefined();
			expect(attr.name).toBe("__nssrc__");
			expect(attr.type).toBe("filtered");
			expect(attr.filter).toBe("[<thisTiddler>!is[blank]] ~[<currentTiddler>]");
		});

		it("uses the ref as link text when no `text|` prefix", function() {
			var link = inline(parse("[[Foo]]"))[0].children[0];
			expect(link.children).toEqual([
				jasmine.objectContaining({type: "text", text: "Foo"})
			]);
		});

		it("splits on `|` for [[text|target]] form", function() {
			var letNode = inline(parse("[[Click here|Foo/Bar]]"))[0];
			// __nsref__ holds the TARGET (after the |), not the text.
			expect(letNode.attributes["__nsref__"].value).toBe("Foo/Bar");
			var link = letNode.children[0];
			expect(link.children[0].text).toBe("Click here");
		});

		it("treats absolute paths as the ref", function() {
			var letNode = inline(parse("[[a/b/c]]"))[0];
			expect(letNode.attributes["__nsref__"].value).toBe("a/b/c");
		});

		it("treats $:/ system titles as the ref", function() {
			var letNode = inline(parse("[[$:/ControlPanel]]"))[0];
			expect(letNode.type).toBe("let");
			expect(letNode.attributes["__nsref__"].value).toBe("$:/ControlPanel");
		});

	});

	describe("external links (preserved verbatim from core)", function() {

		it("emits a plain <a> for http URLs, no $let wrapper", function() {
			var nodes = inline(parse("[[https://example.com]]"));
			expect(nodes.length).toBe(1);
			var a = nodes[0];
			expect(a.type).toBe("element");
			expect(a.tag).toBe("a");
			expect(a.attributes.href.value).toBe("https://example.com");
			expect(a.attributes["class"].value).toBe("tc-tiddlylink-external");
			expect(a.attributes.target.value).toBe("_blank");
			expect(a.attributes.rel.value).toBe("noopener noreferrer");
		});

		it("emits external <a> for [[text|http://...]] form too", function() {
			var a = inline(parse("[[click|https://example.com]]"))[0];
			expect(a.tag).toBe("a");
			expect(a.attributes.href.value).toBe("https://example.com");
			expect(a.children[0].text).toBe("click");
		});

	});

	describe("multiple links in one tiddler", function() {

		it("each link gets its own $let scope (no __nsref__ collision)", function() {
			var nodes = inline(parse("[[A]] and [[B]]"));
			// Two $let nodes (with a text node between them).
			var lets = nodes.filter(function(n) { return n.type === "let"; });
			expect(lets.length).toBe(2);
			expect(lets[0].attributes["__nsref__"].value).toBe("A");
			expect(lets[1].attributes["__nsref__"].value).toBe("B");
		});

	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-relink.js":{"title":"$:/plugins/rimir/namespace/test/test-relink.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-relink.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for relink integration — verifies that renaming a tiddler updates
`\context` pragmas and `<$context>` widget attributes that reference it.

Requires the relink plugin to be loaded in the test wiki.

\*/

"use strict";

describe("namespace: relink integration", function() {

	// Guard: skip all specs if the relink plugin's runtime isn't actually
	// active. A bare presence of the relink plugin tiddler and the core's
	// own relinkTiddler is not enough — we need the override patched in by
	// flibbles' bulkops.js startup module. Probe by running a no-op rename
	// against a temp wiki and checking that a `\context` reference was
	// rewritten (which only the relink wikitextrule pipeline can do).
	function relinkActuallyWorks() {
		try {
			var probe = new $tw.Wiki();
			probe.addTiddler({title: "_p", text: "\\context xx\nbody"});
			probe.relinkTiddler("xx", "yy");
			var t = probe.getTiddler("_p");
			return t && t.fields.text.indexOf("\\context yy") === 0;
		} catch(e) {
			return false;
		}
	}

	if(!relinkActuallyWorks()) {
		it("relink plugin not loaded — skipping relink tests", function() {
			pending("relink plugin not active in this test edition");
		});
		return;
	}

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		// Copy relink plugin shadow tiddlers into the test wiki so
		// relinkTiddler has its full infrastructure.
		$tw.wiki.each(function(tiddler, title) {
			if(title.indexOf("$:/plugins/flibbles/relink") === 0) {
				wiki.addTiddler(tiddler);
			}
		});
		$tw.wiki.eachShadow(function(tiddler, title) {
			if(title.indexOf("$:/plugins/flibbles/relink") === 0) {
				wiki.addTiddler(tiddler);
			}
		});
		// Add the namespace plugin's relink config tiddler.
		wiki.addTiddler({
			title: "$:/config/flibbles/relink/attributes/$context/prefix",
			text: "title"
		});
		wiki.addTiddlers(tiddlers || []);
		wiki.addIndexersToWiki();
		return wiki;
	}

	describe("\\context pragma", function() {

		it("updates prefix when referenced tiddler is renamed", function() {
			var wiki = setupWiki([
				{title: "page", text: "\\context old/prefix\n\nsome body"}
			]);
			wiki.relinkTiddler("old/prefix", "new/prefix");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("\\context new/prefix\n\nsome body");
		});

		it("preserves single trailing newline", function() {
			var wiki = setupWiki([
				{title: "page", text: "\\context old/prefix\nsome body"}
			]);
			wiki.relinkTiddler("old/prefix", "new/prefix");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("\\context new/prefix\nsome body");
		});

		it("does not change when prefix doesn't match", function() {
			var wiki = setupWiki([
				{title: "page", text: "\\context unrelated/prefix\nsome body"}
			]);
			wiki.relinkTiddler("old/prefix", "new/prefix");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("\\context unrelated/prefix\nsome body");
		});

		it("handles prefix with deep path", function() {
			var wiki = setupWiki([
				{title: "page", text: "\\context OWASP/ASVS/4.0.3\n\nbody"}
			]);
			wiki.relinkTiddler("OWASP/ASVS/4.0.3", "OWASP/ASVS/5.0");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("\\context OWASP/ASVS/5.0\n\nbody");
		});

	});

	describe("<$context> widget", function() {

		it("updates prefix attribute when referenced tiddler is renamed", function() {
			var wiki = setupWiki([
				{title: "page", text: "<$context prefix=\"old/prefix\">\nbody\n</$context>"}
			]);
			wiki.relinkTiddler("old/prefix", "new/prefix");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("<$context prefix=\"new/prefix\">\nbody\n</$context>");
		});

		it("does not change when prefix doesn't match", function() {
			var wiki = setupWiki([
				{title: "page", text: "<$context prefix=\"unrelated\">\nbody\n</$context>"}
			]);
			wiki.relinkTiddler("old/prefix", "new/prefix");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("<$context prefix=\"unrelated\">\nbody\n</$context>");
		});

	});

	describe("[[ref]] prettylink", function() {

		// Resolver feature flags need to be enabled per-test for short refs
		// to resolve via walk-up / context / self-prefix.
		function setupWithFlags(tiddlers, opts) {
			opts = opts || {};
			var wiki = setupWiki(tiddlers);
			if(opts.walkUp !== false) {
				wiki.addTiddler({title: "$:/config/rimir/namespace/walk-up", text: "yes"});
			}
			if(opts.selfPrefix) {
				wiki.addTiddler({title: "$:/config/rimir/namespace/self-prefix", text: "yes"});
			}
			if(opts.implicitContext) {
				wiki.addTiddler({title: "$:/config/rimir/namespace/implicit-context", text: "yes"});
			}
			// Re-invalidate the flag cache so new config is read.
			require("$:/plugins/rimir/namespace/featureflags.js").invalidate();
			return wiki;
		}

		it("rewrites an absolute literal ref to the new absolute title", function() {
			var wiki = setupWithFlags([
				{title: "page", text: "see [[knowledge/llm/foo]]"},
				{title: "knowledge/llm/foo", text: ""}
			]);
			wiki.relinkTiddler("knowledge/llm/foo", "knowledge/ai/foo");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("see [[knowledge/ai/foo]]");
		});

		it("preserves [[label|target]] form, updating only the target", function() {
			var wiki = setupWithFlags([
				{title: "page", text: "[[friendly|knowledge/llm/foo]]"},
				{title: "knowledge/llm/foo", text: ""}
			]);
			wiki.relinkTiddler("knowledge/llm/foo", "knowledge/ai/foo");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("[[friendly|knowledge/ai/foo]]");
		});

		it("smart-shortens a walk-up-resolved short ref when the new title has a valid shorter form", function() {
			var wiki = setupWithFlags([
				{title: "knowledge/llm/foo", text: "see [[bar]]"},
				{title: "knowledge/llm/bar", text: ""}
			]);
			wiki.relinkTiddler("knowledge/llm/bar", "knowledge/ai/bar");
			// Smart shortening tries: [[bar]] (no, walk-up doesn't reach
			// the new location), [[ai/bar]] (yes, walk-up via knowledge → ai/bar).
			expect(wiki.getTiddler("knowledge/llm/foo").fields.text)
				.toBe("see [[ai/bar]]");
		});

		it("leaves a walk-up short ref unchanged when target stays reachable post-rename", function() {
			// The ref text equals the new target's last segment AND the new
			// target lives on the source's walk-up path — so walk-up still
			// resolves the unchanged ref to the new title.
			var wiki = setupWithFlags([
				{title: "a/b/c", text: "see [[X]]"},
				{title: "a/b/X", text: ""}
			]);
			wiki.relinkTiddler("a/b/X", "a/X");
			// From a/b/c, [[X]] post-rename: walk-up tries a/b/c/X (no),
			// a/b/X (gone), a/X (yes). Resolves to the new title — no rewrite.
			expect(wiki.getTiddler("a/b/c").fields.text).toBe("see [[X]]");
		});

		it("does not touch refs that resolve to a different tiddler", function() {
			var wiki = setupWithFlags([
				{title: "knowledge/llm/foo", text: "see [[bar]] and [[unrelated]]"},
				{title: "knowledge/llm/bar", text: ""},
				{title: "unrelated", text: ""}
			]);
			wiki.relinkTiddler("knowledge/llm/bar", "knowledge/ai/bar");
			// [[bar]] gets smart-shortened to [[ai/bar]]; [[unrelated]]
			// resolves to a different tiddler so it stays put.
			expect(wiki.getTiddler("knowledge/llm/foo").fields.text)
				.toBe("see [[ai/bar]] and [[unrelated]]");
		});

		it("does not touch external links", function() {
			var wiki = setupWithFlags([
				{title: "page", text: "[[https://example.com]]"}
			]);
			wiki.relinkTiddler("https://example.com", "https://other.com");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("[[https://example.com]]");
		});

		it("rewrites a context-resolved short ref", function() {
			var wiki = setupWithFlags([
				{title: "page", context: "knowledge/llm", text: "[[bar]]"},
				{title: "knowledge/llm/bar", text: ""}
			], {implicitContext: true});
			wiki.relinkTiddler("knowledge/llm/bar", "knowledge/ai/bar");
			expect(wiki.getTiddler("page").fields.text)
				.toBe("[[bar|knowledge/ai/bar]]");
		});

		it("smart-shortens a self-prefix-resolved short ref to the new path's last segments", function() {
			var wiki = setupWithFlags([
				{title: "knowledge/llm/v4", text: "see [[notes/foo]]"},
				{title: "knowledge/llm/v4/notes/foo", text: ""}
			], {selfPrefix: true});
			wiki.relinkTiddler(
				"knowledge/llm/v4/notes/foo",
				"knowledge/llm/v4/articles/foo"
			);
			// Smart shortening tries [[foo]] (walk-up from v4 can't find it),
			// then [[articles/foo]] which self-prefix resolves to the new
			// title. That's the rewrite.
			expect(wiki.getTiddler("knowledge/llm/v4").fields.text)
				.toBe("see [[articles/foo]]");
		});

		it("user's example: rename a/b/c/d → a/b/c/e from source a/b/c shortens [[d]] to [[e]]", function() {
			var wiki = setupWithFlags([
				{title: "a/b/c", text: "[[d]]"},
				{title: "a/b/c/d", text: ""}
			], {selfPrefix: true});
			wiki.relinkTiddler("a/b/c/d", "a/b/c/e");
			expect(wiki.getTiddler("a/b/c").fields.text).toBe("[[e]]");
		});

		it("preserves segment-count when rewriting: [[b/c/d]] from a/b/c → [[f/c/d]] (rename a/b → a/f cascade)", function() {
			// Source a/b/c references a deep descendant via 3-segment ref.
			// User renames a/b → a/f, cascading to rename a/b/c → a/f/c and
			// a/b/c/d → a/f/c/d. We expect the 3-segment ref to keep its
			// 3-segment shape rather than collapse to [[d]].
			var wiki = setupWithFlags([
				{title: "a/b", text: ""},
				{title: "a/b/c", text: "[[b/c/d]]"},
				{title: "a/b/c/d", text: ""}
			]);
			function renameTiddler(from, to) {
				wiki.relinkTiddler(from, to);
				var t = wiki.getTiddler(from);
				if(t) {
					var fields = $tw.utils.extend({}, t.fields, {title: to});
					wiki.deleteTiddler(from);
					wiki.addTiddler(new $tw.Tiddler(fields));
				}
			}
			// Cascade bottom-up: rename child first so its text gets a chance
			// to be relinked while parents are still at their old titles.
			renameTiddler("a/b/c/d", "a/f/c/d");
			renameTiddler("a/b/c", "a/f/c");
			renameTiddler("a/b", "a/f");
			expect(wiki.getTiddler("a/f/c").fields.text).toBe("[[f/c/d]]");
		});

		it("user-reported flow: relinkTiddler with relink-titles cascade rewrites [[b/c/d]] → [[f/c/d]]", function() {
			// Skip if relink-titles isn't actually wired up — copying its
			// shadow tiddlers into a fresh wiki doesn't re-run the
			// relinktitlesrule module registration.
			var hasRelinkTitles = false;
			if($tw.modules && $tw.modules.types && $tw.modules.types.relinktitlesrule) {
				hasRelinkTitles = !!$tw.modules.types.relinktitlesrule[
					"$:/plugins/flibbles/relink-titles/rules/directory"];
			}
			if(!hasRelinkTitles) { pending("relink-titles not loaded as a module"); return; }
			var wiki = setupWithFlags([
				{title: "a/b", text: ""},
				{title: "a/b/c", text: "[[b/c/d]]"},
				{title: "a/b/c/d", text: ""}
			]);
			// Rename the source itself + run relink (UI's typical flow).
			var t = wiki.getTiddler("a/b");
			wiki.deleteTiddler("a/b");
			wiki.addTiddler(new $tw.Tiddler($tw.utils.extend({}, t.fields, {title: "a/f"})));
			wiki.relinkTiddler("a/b", "a/f");
			// relink-titles' directory rule cascades child renames within
			// this single relinkTiddler call. By the time our rule fires
			// on the nested rename of a/b/c/d, the original is already
			// deleted — wrapWikiForPreRename keeps it visible to the
			// resolver so the ref's resolution is detectable.
			expect(wiki.getTiddler("a/f/c")).toBeDefined();
			expect(wiki.getTiddler("a/f/c/d")).toBeDefined();
			expect(wiki.getTiddler("a/f/c").fields.text).toBe("[[f/c/d]]");
		});

		it("handles batch rename of a subtree (knowledge/llm → knowledge/ai)", function() {
			// Mirrors a relink-titles cascading rename. Each child is renamed
			// individually: (1) update references, (2) move the tiddler.
			// Both notes reference each other.
			var wiki = setupWithFlags([
				{title: "knowledge/llm/foo", text: "see [[bar]]"},
				{title: "knowledge/llm/bar", text: "see [[foo]]"}
			]);

			function renameTiddler(from, to) {
				// Update references first so they capture the pre-rename state.
				wiki.relinkTiddler(from, to);
				// Then move the actual tiddler.
				var t = wiki.getTiddler(from);
				if(t) {
					var fields = $tw.utils.extend({}, t.fields, {title: to});
					wiki.deleteTiddler(from);
					wiki.addTiddler(new $tw.Tiddler(fields));
				}
			}

			// Step 1: rename knowledge/llm/foo → knowledge/ai/foo.
			renameTiddler("knowledge/llm/foo", "knowledge/ai/foo");
			// knowledge/llm/bar's [[foo]] resolved (via walk-up) to knowledge/llm/foo
			// = fromTitle. Smart shortening finds "ai/foo" works post-rename
			// (walk-up from knowledge/llm/bar climbs to knowledge/, then
			// "knowledge/ai/foo" exists).
			expect(wiki.getTiddler("knowledge/llm/bar").fields.text)
				.toBe("see [[ai/foo]]");

			// Step 2: rename knowledge/llm/bar → knowledge/ai/bar.
			renameTiddler("knowledge/llm/bar", "knowledge/ai/bar");
			// knowledge/ai/bar (was knowledge/llm/bar) now has "see [[ai/foo]]".
			// That ref resolves to knowledge/ai/foo via walk-up — unchanged.
			// knowledge/ai/foo's [[bar]] still says [[bar]] in raw text (its
			// resolution was never to knowledge/llm/bar, since walk-up from
			// ai/foo climbs to knowledge/ where ai/bar appears at the right
			// time). Both end-state texts are functional.
			expect(wiki.getTiddler("knowledge/ai/bar").fields.text)
				.toBe("see [[ai/foo]]");
			expect(wiki.getTiddler("knowledge/ai/foo").fields.text)
				.toBe("see [[bar]]");
		});

		it("rewrites [[label|target]] target with a smart-shortened form when available", function() {
			var wiki = setupWithFlags([
				{title: "knowledge/llm/foo", text: "[[click here|bar]]"},
				{title: "knowledge/llm/bar", text: ""}
			]);
			// Rename within walk-up scope: bar → bar2 inside same parent.
			wiki.relinkTiddler("knowledge/llm/bar", "knowledge/llm/bar2");
			// Label preserved; target shortened (bar2 resolves via walk-up).
			expect(wiki.getTiddler("knowledge/llm/foo").fields.text)
				.toBe("[[click here|bar2]]");
		});

	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-resolver.js":{"title":"$:/plugins/rimir/namespace/test/test-resolver.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-resolver.js
type: application/javascript
tags: [[$:/tags/test-spec]]

Tests for the namespace resolver — splitPath + the full resolve pipeline
(literal, alias, mount, pseudo, context, walk-up, unresolved) including
their interactions.

\*/

"use strict";

describe("namespace: resolver", function() {

	var resolver = require("$:/plugins/rimir/namespace/resolver.js");
	var aliases = require("$:/plugins/rimir/namespace/aliases.js");
	var mounts = require("$:/plugins/rimir/namespace/mounts.js");
	var flags = require("$:/plugins/rimir/namespace/featureflags.js");

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		// Enable all feature flags so existing tests pass unchanged.
		wiki.addTiddler({title: "$:/config/rimir/namespace/walk-up", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/aliases", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/pseudo-expansion", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/implicit-context", text: "yes"});
		wiki.addIndexersToWiki();
		return wiki;
	}

	beforeEach(function() {
		flags.invalidate();
		resolver.invalidatePseudoCache();
		aliases.invalidateAliases();
		mounts.invalidateMounts();
	});

	describe("splitPath", function() {

		it("splits a regular title on /", function() {
			expect(resolver.splitPath("a/b/c")).toEqual(["a", "b", "c"]);
		});

		it("returns a single segment for no-slash titles", function() {
			expect(resolver.splitPath("foo")).toEqual(["foo"]);
		});

		it("splits $:/ titles with $: as the root segment", function() {
			expect(resolver.splitPath("$:/plugins/foo/bar"))
				.toEqual(["$:", "plugins", "foo", "bar"]);
		});

		it("handles bare $:/ as a single $: segment", function() {
			expect(resolver.splitPath("$:/")).toEqual(["$:"]);
		});

		it("returns empty for null/empty input", function() {
			expect(resolver.splitPath("")).toEqual([]);
			expect(resolver.splitPath(null)).toEqual([]);
			expect(resolver.splitPath(undefined)).toEqual([]);
		});

	});

	describe("resolve — literal", function() {

		it("finds an exact tiddler title", function() {
			var wiki = setupWiki([{title: "Foo", text: ""}]);
			var r = resolver.resolve("Foo", null, wiki);
			expect(r.status).toBe("literal");
			expect(r.resolved).toBe("Foo");
		});

		it("returns unresolved for a missing ref", function() {
			var wiki = setupWiki([]);
			var r = resolver.resolve("Missing", null, wiki);
			expect(r.status).toBe("unresolved");
			expect(r.resolved).toBeNull();
		});

		it("beats alias / mount / pseudo when the raw ref exists", function() {
			var wiki = setupWiki([
				{title: "V3.3", text: "I am literally V3.3"},
				{title: "a/V3.3", text: ""},
				// Alias that would rewrite V3.3 → a/V3.3
				{title: "$:/ns-alias", tags: "$:/tags/NamespaceAlias", "short": "V3.3", "expands-to": "a/V3.3"}
			]);
			var r = resolver.resolve("V3.3", "some/source", wiki);
			expect(r.status).toBe("literal");
			expect(r.resolved).toBe("V3.3");
		});

	});

	describe("resolve — absolute (has /)", function() {

		it("finds an exact-match absolute title", function() {
			var wiki = setupWiki([{title: "a/b/c", text: ""}]);
			var r = resolver.resolve("a/b/c", null, wiki);
			expect(r.status).toBe("literal");
			expect(r.resolved).toBe("a/b/c");
		});

		it("is unresolved if the absolute path misses", function() {
			var wiki = setupWiki([{title: "a/b/c", text: ""}]);
			var r = resolver.resolve("a/b/missing", null, wiki);
			expect(r.status).toBe("unresolved");
			expect(r.resolved).toBeNull();
		});

		it("walks up multi-segment refs to find an ancestor match", function() {
			// REF contains '/', but it's a relative subpath — walk-up still
			// applies and finds the ancestor candidate.
			var wiki = setupWiki([{title: "a/b/c/d", text: ""}]);
			var r = resolver.resolve("c/d", "a/b/source", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/b/c/d");
		});

		it("walk-up tries the deepest ancestor first for multi-segment refs", function() {
			// Both a/b/X/Y and a/X/Y exist; from source a/b/c the walk-up
			// should hit a/b/X/Y (closest ancestor) before a/X/Y.
			var wiki = setupWiki([
				{title: "a/b/X/Y", text: ""},
				{title: "a/X/Y", text: ""}
			]);
			var r = resolver.resolve("X/Y", "a/b/c", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/b/X/Y");
		});

		it("system-namespace refs ($:/...) never walk up or use context", function() {
			// $:/foo is treated as absolute; even if walk-up could synthesize
			// a hit, it's skipped to avoid degenerate $:/REF matches.
			var wiki = setupWiki([{title: "$:/foo", text: ""}]);
			var r = resolver.resolve("$:/missing", "$:/plugins/x/source", wiki);
			expect(r.status).toBe("unresolved");
		});

	});

	describe("resolve — walk-up", function() {

		it("walks up single step", function() {
			var wiki = setupWiki([{title: "a/b/X", text: ""}]);
			var r = resolver.resolve("X", "a/b/source", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/b/X");
		});

		it("walks up multiple steps to the first hit", function() {
			var wiki = setupWiki([{title: "a/Y", text: ""}]);
			var r = resolver.resolve("Y", "a/b/c/source", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/Y");
		});

		it("is unresolved when no ancestor has the name", function() {
			var wiki = setupWiki([]);
			var r = resolver.resolve("Z", "a/b/c/source", wiki);
			expect(r.status).toBe("unresolved");
		});

		it("walks up within $:/ titles too", function() {
			var wiki = setupWiki([{title: "$:/plugins/foo/Y", text: ""}]);
			var r = resolver.resolve("Y", "$:/plugins/foo/bar/source", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("$:/plugins/foo/Y");
		});

		it("does not reach '$:/Y' from $:/ sources (min-depth 2)", function() {
			// If we walked down to depth 1 for $:/ paths we'd try "$:/Y",
			// which is a valid-looking but rarely-intended match.
			var wiki = setupWiki([{title: "$:/Y", text: ""}]);
			var r = resolver.resolve("Y", "$:/plugins/foo/X", wiki);
			expect(r.status).toBe("unresolved");
		});

		it("shadow tiddlers count as hits", function() {
			// Stub wiki that claims "a/Y" as a shadow. Aliases/mounts modules
			// also call filterTiddlers — no-op stub is enough since we
			// don't exercise those rewrites here.
			var fakeWiki = {
				tiddlerExists: function(t) { return false; },
				isShadowTiddler: function(t) { return t === "a/Y"; },
				filterTiddlers: function() { return []; },
				getTiddler: function() { return null; },
				getTiddlerText: function(title, fallback) {
					// Feature flags: enable walk-up for this test.
					if(title === "$:/config/rimir/namespace/walk-up") { return "yes"; }
					return fallback || "";
				},
				each: function() {},
				eachShadow: function() {}
			};
			var r = resolver.resolve("Y", "a/b/source", fakeWiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/Y");
		});

	});

	describe("resolve — context", function() {

		it("uses context prefix when walk-up would miss", function() {
			var wiki = setupWiki([{title: "ctx/X", text: ""}]);
			var r = resolver.resolve("X", "some/source", wiki, {context: "ctx"});
			expect(r.status).toBe("context");
			expect(r.resolved).toBe("ctx/X");
		});

		it("applies context to multi-segment refs too", function() {
			var wiki = setupWiki([{title: "ctx/a/X", text: ""}]);
			var r = resolver.resolve("a/X", "some/source", wiki, {context: "ctx"});
			expect(r.status).toBe("context");
			expect(r.resolved).toBe("ctx/a/X");
		});

		it("doesn't use context if literal already matched", function() {
			var wiki = setupWiki([{title: "X", text: ""}, {title: "ctx/X", text: ""}]);
			var r = resolver.resolve("X", "some/source", wiki, {context: "ctx"});
			expect(r.status).toBe("literal");
			expect(r.resolved).toBe("X");
		});

		it("walk-up tried only if context misses", function() {
			var wiki = setupWiki([{title: "a/X", text: ""}]);
			var r = resolver.resolve("X", "a/b/source", wiki, {context: "wrong-ctx"});
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/X");
		});

	});

	describe("resolve — alias", function() {

		it("rewrites an exact alias", function() {
			var wiki = setupWiki([
				{title: "a/b/X", text: ""},
				{title: "$:/a1", tags: "$:/tags/NamespaceAlias", "short": "SHORT", "expands-to": "a/b/X"}
			]);
			var r = resolver.resolve("SHORT", null, wiki);
			expect(r.status).toBe("alias");
			expect(r.resolved).toBe("a/b/X");
		});

		it("rewrites via pattern alias", function() {
			var wiki = setupWiki([
				{title: "vers/4.0/X", text: ""},
				{title: "$:/a2", tags: "$:/tags/NamespacePatternAlias", pattern: "^V_(.+)$", replacement: "vers/4.0/$1"}
			]);
			var r = resolver.resolve("V_X", null, wiki);
			expect(r.status).toBe("alias");
			expect(r.resolved).toBe("vers/4.0/X");
		});

		it("exact alias wins over pattern alias", function() {
			var wiki = setupWiki([
				{title: "winner", text: ""},
				{title: "loser", text: ""},
				{title: "$:/ex", tags: "$:/tags/NamespaceAlias", "short": "X", "expands-to": "winner"},
				{title: "$:/pat", tags: "$:/tags/NamespacePatternAlias", pattern: "^X$", replacement: "loser"}
			]);
			var r = resolver.resolve("X", null, wiki);
			expect(r.resolved).toBe("winner");
		});

	});

	describe("resolve — mount", function() {

		it("rewrites an exact prefix match", function() {
			var wiki = setupWiki([
				{title: "phys/root/sub", text: ""},
				{title: "$:/m", tags: "$:/tags/NamespaceMount", from: "short", to: "phys/root"}
			]);
			var r = resolver.resolve("short/sub", null, wiki);
			expect(r.status).toBe("mount");
			expect(r.resolved).toBe("phys/root/sub");
		});

		it("rewrites when ref equals 'from' exactly", function() {
			var wiki = setupWiki([
				{title: "phys/root", text: ""},
				{title: "$:/m", tags: "$:/tags/NamespaceMount", from: "short", to: "phys/root"}
			]);
			var r = resolver.resolve("short", null, wiki);
			expect(r.status).toBe("mount");
			expect(r.resolved).toBe("phys/root");
		});

		it("longest 'from' wins", function() {
			var wiki = setupWiki([
				{title: "specific/sub", text: ""},
				{title: "$:/m1", tags: "$:/tags/NamespaceMount", from: "a", to: "generic"},
				{title: "$:/m2", tags: "$:/tags/NamespaceMount", from: "a/b", to: "specific"}
			]);
			var r = resolver.resolve("a/b/sub", null, wiki);
			expect(r.resolved).toBe("specific/sub");
		});

		it("does not match a partial prefix without trailing slash", function() {
			var wiki = setupWiki([
				{title: "$:/m", tags: "$:/tags/NamespaceMount", from: "foo", to: "bar"},
				{title: "barely", text: ""}
			]);
			// "foobar" should NOT match "foo/" pattern
			var r = resolver.resolve("foobar", null, wiki);
			expect(r.status).toBe("unresolved");
		});

	});

	describe("resolve — precedence", function() {

		it("literal beats alias, alias beats mount, mount beats walk-up", function() {
			var wiki = setupWiki([
				// Literal target (highest precedence)
				{title: "TOP", text: ""},
				// Alias → ALIAS/x (second)
				{title: "$:/a", tags: "$:/tags/NamespaceAlias", "short": "ALI", "expands-to": "aliased"},
				{title: "aliased", text: ""},
				// Mount → MOUNT/x (third)
				{title: "$:/m", tags: "$:/tags/NamespaceMount", from: "mnt", to: "mounted"},
				{title: "mounted/x", text: ""},
				// Walk-up target (last)
				{title: "a/WUP", text: ""}
			]);
			expect(resolver.resolve("TOP", "a/b/src", wiki).status).toBe("literal");
			expect(resolver.resolve("ALI", "a/b/src", wiki).status).toBe("alias");
			expect(resolver.resolve("mnt/x", "a/b/src", wiki).status).toBe("mount");
			expect(resolver.resolve("WUP", "a/b/src", wiki).status).toBe("walkup");
		});

	});

	describe("self-prefix", function() {

		// Helper: setupWiki keeps the four pre-existing flags ON (matches the
		// default in this test file). This helper extends it with self-prefix.
		function setupWithSelfPrefix(tiddlers, on) {
			var wiki = setupWiki(tiddlers);
			wiki.addTiddler({title: "$:/config/rimir/namespace/self-prefix", text: on ? "yes" : "no"});
			flags.invalidate();
			return wiki;
		}

		it("is OFF by default — descendants are not auto-resolved", function() {
			var wiki = setupWiki([
				{title: "a/b/c", text: ""},
				{title: "a/b/c/x", text: ""}
			]);
			// No explicit toggle: setupWiki doesn't enable self-prefix.
			expect(resolver.resolve("x", "a/b/c", wiki).status).toBe("unresolved");
		});

		it("resolves a single-segment descendant ref when ON", function() {
			var wiki = setupWithSelfPrefix([
				{title: "a/b/c", text: ""},
				{title: "a/b/c/x", text: ""}
			], true);
			var r = resolver.resolve("x", "a/b/c", wiki);
			expect(r.status).toBe("self");
			expect(r.resolved).toBe("a/b/c/x");
		});

		it("resolves a multi-segment descendant ref when ON", function() {
			var wiki = setupWithSelfPrefix([
				{title: "a/b/c", text: ""},
				{title: "a/b/c/yt/y/z", text: ""}
			], true);
			var r = resolver.resolve("yt/y/z", "a/b/c", wiki);
			expect(r.status).toBe("self");
			expect(r.resolved).toBe("a/b/c/yt/y/z");
		});

		it("falls through to walk-up when no descendant exists", function() {
			var wiki = setupWithSelfPrefix([
				{title: "a/b/c", text: ""},
				{title: "a/x", text: ""}
			], true);
			var r = resolver.resolve("x", "a/b/c", wiki);
			expect(r.status).toBe("walkup");
			expect(r.resolved).toBe("a/x");
		});

		it("Stage 1 literal still wins when a top-level tiddler matches the ref", function() {
			var wiki = setupWithSelfPrefix([
				{title: "x", text: ""},                // top-level literal
				{title: "a/b/c", text: ""},
				{title: "a/b/c/x", text: ""}            // descendant also exists
			], true);
			var r = resolver.resolve("x", "a/b/c", wiki);
			expect(r.status).toBe("literal");
			expect(r.resolved).toBe("x");
		});

		it("Stage 6 context still wins over self-prefix when both would match", function() {
			var wiki = setupWithSelfPrefix([
				{title: "a/b/c", text: ""},
				{title: "ctx/x", text: ""},             // context match
				{title: "a/b/c/x", text: ""}            // self-prefix match
			], true);
			var r = resolver.resolve("x", "a/b/c", wiki, {context: "ctx"});
			expect(r.status).toBe("context");
			expect(r.resolved).toBe("ctx/x");
		});

		it("$:/ ref still short-circuits to unresolved before self-prefix runs", function() {
			// The $:/ guard at resolver.js:300 fires when the REF (not source)
			// starts with $:/. A $:/ ref means "absolute system title" and
			// shouldn't be contextualized or walked.
			var wiki = setupWithSelfPrefix([
				{title: "a/b/c", text: ""},
				{title: "a/b/c/$:/foo", text: ""}    // would self-prefix-match
			], true);
			var r = resolver.resolve("$:/foo", "a/b/c", wiki);
			expect(r.status).toBe("unresolved");
		});

		it("self-prefix runs from a $:/ source — consistent with walk-up", function() {
			// Walk-up runs from $:/ sources (with minI=2). Self-prefix should
			// behave the same: $:/ source + plain ref = system descendant
			// candidate. Allowed because we never construct "$:/<ref>" — only
			// "<source>/<ref>" which is well-formed.
			var wiki = setupWithSelfPrefix([
				{title: "$:/plugins/foo/bar", text: ""},
				{title: "$:/plugins/foo/bar/x", text: ""}
			], true);
			var r = resolver.resolve("x", "$:/plugins/foo/bar", wiki);
			expect(r.status).toBe("self");
			expect(r.resolved).toBe("$:/plugins/foo/bar/x");
		});

	});

});
","type":"application/javascript","tags":"[[$:/tags/test-spec]]"},"$:/plugins/rimir/namespace/test/test-walkup-rendering.js":{"title":"$:/plugins/rimir/namespace/test/test-walkup-rendering.js","text":"/*\
title: $:/plugins/rimir/namespace/test/test-walkup-rendering.js
type: application/javascript
tags: [[$:/tags/test-spec]]

End-to-end regression: walk-up must succeed when wikitext is rendered
through `<$transclude $tiddler=...>`, which sets `thisTiddler` in
TW 5.4.0+ but does NOT set `currentTiddler`. The prettylink rule must
prefer thisTiddler over currentTiddler when picking a source-title
operand for ns-resolve.

Bug history (0.1.12): in knowledge-app, `[[sum]]` from
`knowledge/llm/test/ergo` (with `context: knowledge/llm`) rendered as
ns-unresolved because `<$transclude>` set thisTiddler but the prettylink
filter referenced `<currentTiddler>`, which was empty. Walk-up was
gated by `if(sourceTitle && ...)` and short-circuited.

\*/
"use strict";

describe("namespace: walk-up under transclusion (regression)", function() {

	var resolver = require("$:/plugins/rimir/namespace/resolver.js");
	var aliases = require("$:/plugins/rimir/namespace/aliases.js");
	var mounts = require("$:/plugins/rimir/namespace/mounts.js");
	var flags = require("$:/plugins/rimir/namespace/featureflags.js");

	function setupWiki(tiddlers) {
		var wiki = new $tw.Wiki();
		wiki.addTiddlers(tiddlers || []);
		wiki.addTiddler({title: "$:/config/rimir/namespace/walk-up", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/aliases", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/pseudo-expansion", text: "yes"});
		wiki.addTiddler({title: "$:/config/rimir/namespace/implicit-context", text: "yes"});
		wiki.addIndexersToWiki();
		return wiki;
	}

	beforeEach(function() {
		flags.invalidate();
		resolver.invalidatePseudoCache();
		aliases.invalidateAliases();
		mounts.invalidateMounts();
	});

	function renderHtml(wiki, hostText) {
		wiki.addTiddler({title: "host", text: hostText});
		var widget = wiki.makeTranscludeWidget("host",
			{parseAsInline: false, document: $tw.fakeDocument});
		var container = $tw.fakeDocument.createElement("div");
		widget.render(container, null);
		return container.outerHTML || "";
	}

	it("[[sum]] resolves via walk-up when rendered through $transclude $tiddler=", function() {
		var wiki = setupWiki([
			{title: "knowledge/llm/test/ergo", context: "knowledge/llm", text: "[[sum]]"},
			{title: "knowledge/llm/test/sum", text: ""}
		]);
		// Mirror knowledge-app/views/note.tid pattern: outer $context wrap,
		// then $transclude $tiddler=<<viewTiddler>> $mode="block".
		var html = renderHtml(wiki,
			"<$let viewTiddler=\"knowledge/llm/test/ergo\" " +
			"      noteContext={{{ [<viewTiddler>get[context]] }}}>" +
			"<$context prefix=<<noteContext>>>" +
			"<$transclude $tiddler=<<viewTiddler>> $mode=\"block\"/>" +
			"</$context>" +
			"</$let>");
		expect(html).toContain("ns-resolved\"");
		expect(html).not.toContain("ns-unresolved");
	});

	it("[[test/sum]] also walks up under $transclude (multi-segment ref)", function() {
		var wiki = setupWiki([
			{title: "knowledge/llm/test/ergo", context: "knowledge/llm", text: "[[test/sum]]"},
			{title: "knowledge/llm/test/sum", text: ""}
		]);
		var html = renderHtml(wiki,
			"<$let viewTiddler=\"knowledge/llm/test/ergo\">" +
			"<$transclude $tiddler=<<viewTiddler>> $mode=\"block\"/>" +
			"</$let>");
		expect(html).toContain("ns-resolved\"");
		expect(html).not.toContain("ns-unresolved");
	});

	it("genuinely unresolved refs still get ns-unresolved", function() {
		var wiki = setupWiki([
			{title: "a/b/c", text: "[[Nope]]"}
		]);
		var html = renderHtml(wiki,
			"<$transclude $tiddler=\"a/b/c\" $mode=\"block\"/>");
		expect(html).toContain("ns-unresolved");
	});

	it("self-prefix resolves descendant refs end-to-end (knowledge-app scenario)", function() {
		// Mirrors knowledge-app/views/note.tid — outer $context wraps body,
		// inner $transclude $tiddler= sets thisTiddler. Source has the
		// (current default) context: knowledge/llm field, which would make
		// Stage 6 try knowledge/llm/yt/... first (no match) — self-prefix
		// then catches the descendant.
		var wiki = setupWiki([
			{
				title: "knowledge/llm/vendor/deepseek/model/v4",
				context: "knowledge/llm",
				text: "[[yt/AIsearch/engineeringDSV4]]"
			},
			{title: "knowledge/llm/vendor/deepseek/model/v4/yt/AIsearch/engineeringDSV4", text: ""}
		]);
		wiki.addTiddler({title: "$:/config/rimir/namespace/self-prefix", text: "yes"});
		flags.invalidate();
		var html = renderHtml(wiki,
			"<$let viewTiddler=\"knowledge/llm/vendor/deepseek/model/v4\" " +
			"      noteContext={{{ [<viewTiddler>get[context]] }}}>" +
			"<$context prefix=<<noteContext>>>" +
			"<$transclude $tiddler=<<viewTiddler>> $mode=\"block\"/>" +
			"</$context>" +
			"</$let>");
		expect(html).toContain("ns-resolved\"");
		expect(html).not.toContain("ns-unresolved");
		// Sanity: link target is the descendant, not the area-prepended path.
		// TW URL-encodes "/" to %2F in href, so check the encoded form.
		expect(html).toContain("knowledge%2Fllm%2Fvendor%2Fdeepseek%2Fmodel%2Fv4%2Fyt%2FAIsearch%2FengineeringDSV4");
	});

	it("self-prefix off — same scenario stays unresolved (regression guard)", function() {
		var wiki = setupWiki([
			{
				title: "knowledge/llm/vendor/deepseek/model/v4",
				context: "knowledge/llm",
				text: "[[yt/AIsearch/engineeringDSV4]]"
			},
			{title: "knowledge/llm/vendor/deepseek/model/v4/yt/AIsearch/engineeringDSV4", text: ""}
		]);
		// Don't enable self-prefix; default is off.
		var html = renderHtml(wiki,
			"<$let viewTiddler=\"knowledge/llm/vendor/deepseek/model/v4\" " +
			"      noteContext={{{ [<viewTiddler>get[context]] }}}>" +
			"<$context prefix=<<noteContext>>>" +
			"<$transclude $tiddler=<<viewTiddler>> $mode=\"block\"/>" +
			"</$context>" +
			"</$let>");
		expect(html).toContain("ns-unresolved");
	});

});
